INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-21', E'이스라엘의 사사들 (사사기 4장)', E'사사기 4장', E'여호와를 떠났던 이스라엘은 다시 심판의 때를 맞이합니다. 사사 에훗이 죽은 후 또다시 악을 행한 이스라엘에게 하나님께서는 가나안 왕 야빈의 손에 그들을 넘기셨습니다. 철병거 구백 대를 보유한 압도적인 군사력으로 야빈은 이십 년 동안 이스라엘을 학대했고, 고통에 짓눌린 백성들은 여호와께 부르짖게 됩니다.\n\n이때 하나님께서 준비하신 인물은 여선지자 드보라였습니다. 에브라임 산지의 종려나무 아래서 백성들의 재판을 맡았던 그녀는 하나님의 음성을 듣고 바락을 불러 구원의 계획을 전합니다. 그러나 바락은 드보라가 함께하지 않으면 가지 않겠다는 연약함을 보입니다. 드보라의 예언대로 전쟁의 영광은 여인의 손에 돌아가게 됩니다.\n\n다볼 산 전투에서 하나님께서는 친히 이스라엘을 위해 싸우셨습니다. 철병거로 무장한 시스라의 군대는 여호와 앞에서 혼란에 빠졌고, 대장 시스라는 병거를 버리고 도망쳤습니다. 그가 숨어든 곳은 겐 사람 헤벨의 아내 야엘의 장막이었습니다. 야엘은 시스라를 영접하여 안심시킨 후, 그가 깊이 잠들었을 때 장막 말뚝을 그의 관자놀이에 박아 죽였습니다.\n\n이 사건은 단순한 전쟁 이야기가 아닙니다. 하나님께서는 당시 사회에서 연약한 존재로 여겨졌던 여인들을 통해 구원의 역사를 이루셨습니다. 드보라와 야엘, 두 여인의 용기와 순종은 하나님께서 사용하시는 도구에는 제한이 없음을 보여줍니다. 철병거와 군사력을 자랑하던 가나안의 압제는 하나님을 의지한 믿음의 사람들 앞에서 무너졌고, 이스라엘은 다시 한 번 여호와께서 그들과 함께하심을 경험하게 되었습니다.', E'오늘의 핵심\n하나님께서는 드보라와 야엘이라는 두 여인을 통해 철병거로 무장한 가나안의 압제를 무너뜨리시고, 누구든지 믿음으로 순종할 때 구원의 도구로 사용하심을 보여주십니다.\n\n묵상 질문\n1. 바락처럼 하나님의 부르심 앞에서 주저하고 있는 영역은 무엇인가요?\n2. 드보라와 야엘처럼 하나님께서 나를 통해 이루고자 하시는 일은 무엇일까요?\n3. 세상의 힘과 권세 앞에서도 하나님을 신뢰하며 나아갈 용기가 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-22', E'이스라엘의 사사들 (사사기 5장)', E'사사기 5장', E'승리의 노래가 이스라엘 진영에 울려 퍼집니다. 드보라와 바락이 함께 부르는 이 찬양은 단순한 전승가가 아니라 하나님의 구원 역사를 기념하는 신앙 고백입니다. 사사 시대의 어두운 터널 속에서도 하나님께서는 당신의 백성을 포기하지 않으셨음을 이 노래는 증거하고 있습니다.\n\n드보라의 노래는 먼저 하나님의 권능을 찬양합니다. "산들이 여호와 앞에서 진동하니"(삿 5:5)라는 고백처럼, 창조주 하나님께서 친히 이스라엘을 위해 싸우셨음을 선포합니다. 별들까지도 하늘에서 시스라와 싸웠다는 시적 표현은 온 우주가 하나님의 뜻에 따라 움직였음을 보여줍니다. 이스라엘의 승리는 군사력이나 전략의 우수함 때문이 아니라 전적으로 하나님의 개입하심 때문이었습니다.\n\n그러나 이 찬양시는 또한 뼈아픈 현실도 드러냅니다. 모든 지파가 하나님의 부르심에 응답한 것은 아니었습니다. 르우벤은 양 우리에 머물렀고, 단은 배에, 아셀은 해변에 머물렀습니다. 특히 메로스 주민들은 여호와를 돕지 않았다는 이유로 저주를 받습니다. 반면 스불론과 납달리는 죽음을 무릅쓰고 헌신했으며, 이방 여인 야엘까지도 하나님의 구원 역사에 동참했습니다.\n\n드보라는 자신을 "이스라엘의 어머니"라고 부릅니다. 신앙의 다음 세대를 제대로 양육하지 못해 어두운 시대가 도래했지만, 하나님께서는 한 여인을 통해 다시 당신의 백성을 일으키셨습니다. 마치 한나가 사무엘을 통해 새 시대를 준비했듯이, 드보라를 통해 절망의 시대에 희망의 빛을 비추신 것입니다.\n\n이 승리의 노래는 "주를 사랑하는 자들은 해가 힘 있게 돋음 같게 하시옵소서"라는 기도로 마무리됩니다. 어둠을 뚫고 떠오르는 태양처럼, 하나님을 사랑하는 이들이 시대의 어둠을 밝히는 빛이 되기를 소망하는 것입니다. 사십 년의 평화는 이런 신앙의 열매였습니다.', E'오늘의 핵심\n드보라의 승리의 노래는 하나님의 권능과 신실하심을 찬양하면서도, 믿음의 응답에 따라 나뉘는 백성들의 모습을 통해 우리의 헌신을 돌아보게 합니다.\n\n묵상 질문\n1. 하나님의 부르심에 나는 어떻게 응답하고 있나요? 르우벤처럼 머뭇거리고 있지는 않나요?\n2. 드보라처럼 어두운 시대에 빛이 되기 위해 내가 감당해야 할 역할은 무엇일까요?\n3. "주를 사랑하는 자들은 해가 힘 있게 돋음 같게" 되려면 어떤 삶을 살아야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-23', E'기드온과 3백 용사 (사사기 6장)', E'사사기 6장', E'이스라엘 백성이 또다시 여호와 앞에서 악을 행하자, 하나님께서는 7년 동안 그들을 미디안의 손에 넘기십니다. 미디안의 압제는 극심하여 이스라엘 백성은 산에 굴을 파고 숨어 살아야 했고, 파종한 곡식마저 메뚜기 떼처럼 몰려온 적들에게 모두 빼앗겼습니다. 궁핍함이 극에 달하자 이스라엘은 여호와께 부르짖었고, 하나님은 먼저 선지자를 보내어 그들의 불순종을 지적하십니다. 출애굽의 은혜를 잊고 가나안의 신들을 섬긴 것이 오늘의 고난을 자초했다는 것입니다.\n\n이러한 상황에서 하나님은 기드온을 부르십니다. 미디안을 피해 포도주 틀에서 밀을 타작하던 기드온에게 여호와의 사자가 나타나 "큰 용사여 여호와께서 너와 함께 계시도다"라고 선포합니다. 기드온의 반응은 회의적이었습니다. 하나님이 함께하신다면 어찌 이런 고난이 닥쳤겠느냐는 것입니다. 그러나 하나님은 바로 그 기드온을 통해 이스라엘을 구원하시겠다고 약속하십니다. 자신이 므낫세 지파 중 가장 약한 가문의 막내라고 주저하는 기드온에게, 하나님은 "내가 반드시 너와 함께 하리니"라는 확실한 동행의 약속을 주십니다.\n\n기드온이 준비한 제물을 통해 하나님의 임재를 확인한 후, 하나님은 그에게 첫 번째 사명을 주십니다. 바로 아버지 집에 있는 바알 제단을 헐고 아세라 상을 찍어내라는 것입니다. 기드온은 두려움 때문에 밤에 이 일을 수행했지만, 그것은 분명한 신앙의 결단이었습니다. 성읍 사람들이 격분하여 기드온을 죽이려 할 때, 오히려 그의 아버지 요아스가 "바알이 신이라면 스스로 변호하게 하라"며 아들을 변호합니다. 이 사건으로 기드온은 ''여룹바알''(바알이 다투게 하라)이라는 새 이름을 얻게 됩니다. 미디안 연합군이 이스르엘 골짜기에 진을 치자, 여호와의 영이 기드온에게 임하시고, 그의 나팔 소리에 이스라엘 지파들이 모여듭니다.', E'오늘의 핵심\n하나님은 반복되는 이스라엘의 불순종에도 불구하고 다시 구원을 베푸시며, 가장 연약해 보이는 기드온을 선택하여 먼저 우상을 제거하는 영적 개혁부터 시작하게 하십니다.\n\n묵상 질문\n1. 극심한 고난 중에도 하나님이 함께하신다는 약속을 어떻게 신뢰할 수 있을까요?\n2. 기드온처럼 우리 삶에서 먼저 제거해야 할 ''바알의 제단''은 무엇일까요?\n3. 연약함을 핑계로 주저하는 나에게 하나님은 어떤 확신을 주고 계십니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-24', E'기드온과 3백 용사 (사사기 7장)', E'사사기 7장', E'하나님께서는 기드온과 함께 미디안과의 전쟁을 준비하시면서 놀라운 방법으로 일하십니다. 3만 2천 명이나 모인 이스라엘 군대를 보시고는 "너를 따르는 백성이 너무 많은즉 내가 그들의 손에 미디안 사람을 넘겨 주지 아니하리니"(삿 7:2)라고 말씀하십니다. 하나님께서는 이스라엘이 자신들의 힘으로 승리했다고 자랑하지 못하도록, 오직 하나님의 능력으로 구원받음을 분명히 보여주고자 하셨습니다.\n\n두려워 떠는 자들을 돌려보내자 2만 2천 명이 떠났고, 물을 마시는 방법으로 다시 시험하셔서 결국 300명만 남게 하십니다. 손으로 움켜 입에 대고 핥는 자들은 경계를 늦추지 않는 전사의 자세를 보여주었습니다. 하나님께서는 이 소수의 군대로 메뚜기떼처럼 많은 미디안 군대를 물리치실 계획을 세우셨습니다.\n\n여전히 두려워하는 기드온을 위해 하나님께서는 특별한 표징을 준비하십니다. 적진에 내려가 들은 미디안 병사의 꿈 이야기는 하나님께서 이미 승리를 예비하셨음을 확증해 주었습니다. 보리떡 한 덩어리가 미디안 진영을 무너뜨리는 꿈은 보잘것없어 보이는 이스라엘이 하나님의 능력으로 승리할 것을 상징했습니다.\n\n기드온과 300명의 용사들은 나팔과 횃불, 그리고 빈 항아리라는 특별한 무기를 들고 전투에 나섰습니다. "여호와와 기드온의 칼이다"라는 함성과 함께 항아리를 깨뜨리고 횃불을 드러내자, 하나님께서 미디안 진영에 혼란을 일으키셔서 그들이 서로를 치게 하셨습니다. 이 놀라운 승리는 전쟁이 사람의 수나 무기에 달린 것이 아니라 오직 하나님의 손에 달려 있음을 보여줍니다. 하나님께서는 연약한 자를 들어 강한 자를 부끄럽게 하시며, 순종하는 자를 통해 당신의 영광을 나타내십니다.', E'오늘의 핵심\n하나님께서는 300명의 소수 정예만을 남기시고 특별한 방법으로 미디안을 물리치게 하심으로써, 구원이 오직 하나님의 능력으로 이루어짐을 분명히 보여주셨습니다.\n\n묵상 질문\n1. 하나님은 왜 많은 군대를 돌려보내시고 300명만 남기셨을까요?\n2. 나팔과 항아리, 횃불이라는 특별한 무기가 주는 영적 교훈은 무엇일까요?\n3. 내 삶에서도 하나님의 방법이 아닌 내 힘과 능력을 의지하고 있는 영역은 없나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-25', E'기드온과 그 아들 아비멜렉 (사사기 8장)', E'사사기 8장', E'미디안과의 전쟁에서 대승을 거둔 기드온에게 예상치 못한 도전이 찾아옵니다. 에브라임 지파가 전쟁에서 자신들을 소외시켰다며 크게 다투어 온 것입니다. 이스라엘 내부의 분열이 우려되는 순간, 기드온은 놀라운 지혜와 겸손으로 대응합니다. "에브라임의 끝물 포도가 아비에셀의 맏물 포도보다 낫지 아니하냐"(삿 8:2)라며 그들의 공로를 높이 평가하자, 에브라임의 노여움이 풀렸습니다. 승리의 영광을 독차지하지 않고 나누는 기드온의 모습에서 참된 지도자의 덕목이 드러납니다.\n\n그러나 숙곳과 브누엘 사람들의 반응은 사뭇 달랐습니다. 동족인 기드온의 군대가 미디안 왕들을 추격하며 도움을 요청했으나, 그들은 냉담하게 거절했습니다. 아직 전쟁의 승부가 확실하지 않다고 판단한 그들의 계산적인 태도는 하나님의 역사하심을 신뢰하지 못하는 불신앙의 모습이었습니다. 결국 기드온이 승리하고 돌아왔을 때, 그들은 엄중한 심판을 받게 됩니다.\n\n전쟁이 끝난 후 이스라엘 백성들은 기드온에게 왕이 되어달라고 요청합니다. 하지만 기드온은 "여호와께서 너희를 다스리시리라"라고 대답하며 왕권을 거절합니다. 이는 하나님만이 이스라엘의 참된 왕이심을 인정하는 신앙고백이었습니다. 그러나 안타깝게도 기드온은 전리품으로 에봇을 만들어 오브라에 두는 실수를 범합니다. 백성들이 이를 우상처럼 섬기게 되면서, 순수했던 신앙이 변질되기 시작합니다.\n\n기드온이 세상을 떠나자 이스라엘의 영적 상태는 급속히 악화됩니다. 그들은 자신들을 구원하신 하나님을 잊어버리고 다시 바알을 섬기기 시작했습니다. 더욱이 미디안의 압제에서 건져준 기드온의 은혜마저 기억하지 않고 그의 집안을 돌보지 않았습니다. 이는 영적 건망증에 걸린 백성의 배은망덕한 모습을 보여줍니다. 하나님의 은혜를 쉽게 잊어버리는 인간의 연약함이 사사 시대를 더욱 어둡게 만들어가고 있었습니다.', E'오늘의 핵심\n겸손한 지도자 기드온의 지혜로운 대처와 왕권 거절은 하나님 중심의 신앙을 보여주지만, 에봇 제작의 실수와 그의 죽음 후 백성들의 배교는 인간의 연약함을 드러냅니다.\n\n묵상 질문\n1. 자존심이 상하는 상황에서도 겸손하게 대응하려면 어떤 마음가짐이 필요할까요?\n2. 숙곳과 브누엘 사람들처럼 계산적인 신앙의 모습이 내게도 있지는 않은가요?\n3. 하나님의 은혜를 기억하고 감사하는 삶을 위해 무엇을 실천해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-26', E'기드온과 그 아들 아비멜렉 (사사기 9장)', E'사사기 9장', E'기드온이 죽자 이스라엘은 다시 우상숭배의 길로 돌아갔고, 그의 아들 아비멜렉은 권력욕에 눈이 멀어 형제 70명을 한 바위 위에서 죽이는 참혹한 일을 저지릅니다. 세겜 사람들은 바알브릿 신전에서 은 칠십 개를 내어 아비멜렉을 지원했고, 그는 이 돈으로 방탕하고 경박한 사람들을 모아 자신의 형제들을 학살합니다. 유일하게 살아남은 막내 요담은 그리심 산에서 나무들의 비유를 통해 아비멜렉과 세겜 사람들의 어리석음을 폭로합니다. 감람나무, 무화과나무, 포도나무는 각자 소중한 사명이 있어 왕이 되기를 거절했지만, 아무 쓸모없는 가시나무만이 기꺼이 왕이 되려 했다는 이 비유는 아비멜렉의 자격 없음을 신랄하게 지적합니다.\n\n요담의 예언대로 아비멜렉이 이스라엘을 다스린 지 삼 년 만에 하나님께서 악한 영을 보내시어 아비멜렉과 세겜 사람들 사이에 분열이 일어납니다. 에벳의 아들 가알이 나타나 세겜 사람들을 선동하여 아비멜렉을 배반하게 하고, 결국 내분과 전쟁이 일어납니다. 이는 형제들의 피를 흘린 아비멜렉과 그 악행에 동조한 세겜 사람들에 대한 하나님의 심판이었습니다. 권력을 탐한 자와 그를 지지한 자들 모두가 서로를 파멸시키는 비극적 결말은, 하나님을 떠난 인간의 권력욕이 얼마나 파괴적인지를 보여줍니다. 사사 시대의 영적 암흑은 지도자 한 사람의 죽음으로 다시 깊어져 갔고, 백성들은 여전히 참된 왕이신 하나님을 거부한 채 인간 왕을 세우려는 어리석음을 반복하고 있었습니다.', E'오늘의 핵심\n권력욕에 사로잡힌 아비멜렉의 형제 살해와 세겜 사람들의 배반은 하나님을 떠난 인간 사회가 얼마나 잔인하고 자멸적인지를 보여줍니다.\n\n묵상 질문\n1. 요담의 나무 비유에서 가시나무처럼 자격 없이 높은 자리를 탐하는 모습이 내게는 없나요?\n2. 하나님께서 악한 영을 보내어 악인들이 서로 멸하게 하신 것을 통해 무엇을 깨닫게 되나요?\n3. 권력과 지위보다 하나님이 주신 각자의 사명에 충실한 삶을 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-28', E'진정한 지도자가 없다 (사사기 10장)', E'사사기 10장', E'아비멜렉의 폭정이 끝난 후, 돌라와 야일이라는 두 사사가 등장합니다. 돌라는 23년간 이스라엘을 다스렸지만, 그의 업적에 대한 기록은 전무합니다. 야일의 경우는 더욱 특이한데, 성경은 그가 "아들 삼십 명이 있어 어린 나귀 삼십을 탔고 성읍 삼십을 가졌는데"(삿 10:4)라고 기록합니다. 사사로서의 영적 지도력보다는 세속적인 부와 권력을 과시하는 모습이 부각되고 있습니다. 이는 하나님의 백성을 인도해야 할 지도자의 모습과는 거리가 먼 것이었습니다.\n\n야일이 죽은 후, 이스라엘 백성은 다시 우상숭배의 늪에 빠집니다. 바알과 아스다롯뿐 아니라 주변 일곱 민족의 신들까지 섬기며 여호와를 완전히 버렸습니다. 그 결과 블레셋과 암몬의 압제를 18년간 받게 됩니다. 고통 속에서 이스라엘은 여호와께 부르짖지만, 하나님은 냉정하게 말씀하십니다. 과거에 수차례 구원하셨음에도 계속 배신하는 백성에게 "가서 너희가 택한 신들에게 부르짖어 너희의 환난 때에 그들이 너희를 구원하게 하라"고 하신 것입니다.\n\n그러나 백성이 진심으로 회개하며 이방 신들을 제거하고 여호와만을 섬기자, 성경은 감동적인 장면을 보여줍니다. "여호와께서 이스라엘의 곤고로 말미암아 마음에 근심하시니라." 반복되는 배신에도 불구하고 당신의 백성을 향한 하나님의 마음은 여전히 뜨거웠습니다. 이것이 바로 언약의 신실하심이며, 우리를 향한 하나님의 변함없는 사랑입니다. 암몬과의 전쟁을 앞둔 이스라엘은 새로운 지도자를 찾고 있었습니다. 하나님께서는 또다시 구원의 손길을 준비하고 계셨던 것입니다.', E'오늘의 핵심\n반복되는 이스라엘의 배신에도 불구하고, 진정한 회개에는 여전히 마음 아파하시며 구원을 예비하시는 하나님의 신실한 사랑을 보여줍니다.\n\n묵상 질문\n1. 세속적 성공과 부를 자랑하는 야일의 모습에서 오늘날 우리는 무엇을 경계해야 할까요?\n2. 하나님께서 "다시는 구원하지 않겠다"고 하실 때의 마음을 생각해 보셨나요?\n3. 반복되는 실패에도 여전히 나를 향해 근심하시는 하나님의 사랑을 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-29', E'진정한 지도자가 없다 (사사기 11장)', E'사사기 11장', E'길르앗 사람 입다는 큰 용사였으나 기생의 아들이라는 출생의 한계로 인해 형제들로부터 쫓겨난 사람이었습니다. 그가 돕 땅에서 잡류들과 함께 지내고 있을 때, 암몬 자손의 침략을 받은 길르앗 장로들이 그를 찾아와 지도자가 되어달라고 요청합니다. 한때 자신을 내쫓았던 이들의 요청은 아이러니했지만, 입다는 하나님께서 그들을 자신의 손에 넘겨주신다면 지도자가 되겠다고 응답합니다.\n\n입다는 단순히 무력만 앞세우는 용사가 아니었습니다. 암몬 왕과의 외교적 협상에서 그는 이스라엘이 광야에서 가나안으로 들어올 때의 역사를 정확하게 제시하며, 이스라엘이 현재의 땅을 정당하게 차지하게 된 과정을 논리적으로 설명합니다. 특히 "이스라엘의 하나님 여호와께서 이같이 아모리 족속을 자기 백성 이스라엘 앞에서 쫓아내셨거늘 네가 그 땅을 얻고자 하는 것이 옳으냐"(삿 11:23)라는 그의 주장은 하나님의 주권적 역사를 인정하는 신앙적 통찰을 보여줍니다.\n\n하나님의 영이 입다에게 임하시자 그는 암몬과의 전쟁에서 큰 승리를 거두게 됩니다. 그러나 전쟁을 앞두고 한 경솔한 서원이 비극을 낳습니다. 승리 후 자신을 처음 맞이하는 사람을 번제로 드리겠다는 서원은 결국 무남독녀를 잃게 되는 결과를 가져왔습니다. 딸의 성숙한 순종은 아버지의 어리석음을 더욱 부각시킵니다. 입다의 이야기는 하나님께서 부족한 사람도 사용하시지만, 온전한 신앙과 지혜가 없이는 승리도 비극이 될 수 있음을 보여주는 교훈입니다.', E'오늘의 핵심\n하나님은 상처받고 소외된 입다를 들어 쓰셨지만, 그의 경솔한 서원은 승리의 기쁨을 비극으로 바꾸었습니다. 능력만으로는 충분하지 않으며, 하나님의 뜻을 바르게 아는 지혜가 필요합니다.\n\n묵상 질문\n1. 내 삶의 상처와 한계가 오히려 하나님께 쓰임받는 통로가 될 수 있을까요?\n2. 급한 마음에 하나님께 경솔한 약속을 한 적은 없나요?\n3. 하나님이 주신 은사와 능력을 지혜롭게 사용하려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-30', E'진정한 지도자가 없다 (사사기 12장)', E'사사기 12장', E'입다가 승리한 후, 에브라임 지파가 찾아와 항의합니다. 암몬과의 전쟁에 자신들을 부르지 않았다며 입다와 그의 집을 불태우겠다고 위협합니다. 이미 기드온 때도 비슷한 일이 있었는데(삿 8:1-3), 에브라임 지파는 또다시 자존심에 상처를 입었다며 분노를 표출합니다. 입다의 대답은 기드온과 달랐습니다. 그는 에브라임이 도와주지 않아서 혼자 목숨을 걸고 싸웠다고 반박하며, 결국 동족 간의 전쟁으로 번집니다.\n\n길르앗 사람들은 요단 강 나루를 장악하고 도망치는 에브라임 사람들을 가려내는 잔인한 방법을 사용합니다. ''쉽볼렛''이라는 단어를 발음하게 하여, 지역 방언 차이로 ''십볼렛''이라고 발음하는 에브라임 사람들을 찾아내 죽였습니다. 이 내전으로 에브라임 사람 4만 2천 명이 목숨을 잃었습니다. 하나님께서 주신 승리의 기쁨은 동족상잔의 비극으로 얼룩지고 말았습니다.\n\n입다는 6년간 사사로 활동하다 죽었고, 이후 입산, 엘론, 압돈이 차례로 사사가 됩니다. 성경은 이들에 대해 매우 짧게 기록하는데, 특히 입산과 압돈은 많은 자녀를 두고 나귀를 탄 것만 강조됩니다. 이는 야일의 기록과 유사하게, 그들이 개인적 번영과 가문의 영달에는 성공했으나 이스라엘을 영적으로 개혁하는 사명에는 실패했음을 암시합니다. 사사 시대가 깊어갈수록 지도자들의 영적 권위는 약해지고, 백성들은 더욱 하나님에게서 멀어져 갔습니다.', E'오늘의 핵심\n입다의 승리는 동족상잔의 비극으로 이어졌고, 뒤를 이은 사사들도 영적 개혁보다는 개인의 번영에 치중하며 사사 시대의 영적 쇠퇴를 보여줍니다.\n\n묵상 질문\n1. 에브라임 지파의 자존심과 입다의 분노가 빚은 비극에서 무엇을 배울 수 있을까요?\n2. 하나님이 주신 승리와 축복이 교만이나 분열로 변질되지 않으려면 어떻게 해야 할까요?\n3. 내가 맡은 자리에서 개인적 성공보다 하나님의 뜻을 우선하고 있는지 돌아보았나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-01', E'나실인 삼손 (사사기 13장)', E'사사기 13장', E'이스라엘 백성이 또다시 여호와 목전에 악을 행하여 40년간 블레셋의 압제를 받던 암울한 시기에, 하나님께서는 특별한 방법으로 구원자를 예비하십니다. 단 지파 마노아의 아내는 오랫동안 자녀를 갖지 못했지만, 여호와의 사자가 나타나 놀라운 소식을 전합니다. 태어날 아이는 나실인으로 구별되어 블레셋으로부터 이스라엘을 구원하기 시작할 것이라는 약속이었습니다.\n\n나실인은 특별히 하나님께 바쳐진 사람으로, 포도주와 독주를 마시지 않고, 부정한 것을 먹지 않으며, 머리에 삭도를 대지 않는 엄격한 규례를 지켜야 했습니다. 특별한 것은 삼손의 경우 태어나기 전부터 이미 나실인으로 구별되었다는 점입니다. 어머니조차 임신 기간부터 나실인의 규례를 지켜야 했습니다. 이는 하나님께서 이스라엘의 구원을 위해 얼마나 철저히 준비하셨는지를 보여줍니다.\n\n마노아 부부의 반응도 주목할 만합니다. 여호와의 사자를 만난 후 그들은 두려워하면서도 겸손히 하나님의 뜻을 구했습니다. 마노아는 "우리가 그 낳을 아이에게 어떻게 행할지를 우리에게 가르치게 하소서"라고 기도했습니다. 부모로서 하나님의 특별한 계획 앞에 순종하려는 마음이 담겨 있습니다. 여호와의 사자가 제단의 불꽃과 함께 하늘로 올라간 후, 마노아는 하나님을 뵈었다고 두려워했지만, 그의 아내는 믿음의 통찰력으로 하나님께서 그들을 통해 일하실 것임을 확신했습니다.\n\n삼손의 출생은 하나님께서 가장 어두운 시대에도 구원의 계획을 포기하지 않으신다는 증거입니다. 40년이라는 긴 압제의 시간이었지만, 하나님은 한 가정을 통해 새로운 시작을 준비하셨습니다. 소라와 에스다올 사이에서 여호와의 영이 삼손을 움직이기 시작하신 것은, 이제 하나님의 때가 이르렀음을 알리는 신호였습니다.', E'오늘의 핵심\n하나님께서는 이스라엘이 40년간 블레셋의 압제를 받던 어두운 시대에도 포기하지 않으시고, 나실인 삼손을 통해 구원의 역사를 시작하십니다.\n\n묵상 질문\n1. 오랜 기다림 끝에 응답받은 마노아 부부처럼, 나도 하나님의 때를 신뢰하며 기다리고 있나요?\n2. 삼손이 태어나기 전부터 구별되었듯이, 하나님께서 나를 위해 예비하신 특별한 계획이 있음을 믿나요?\n3. 마노아처럼 자녀를 하나님의 뜻대로 양육하기 위해 나는 어떤 노력을 하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-02', E'나실인 삼손 (사사기 14장)', E'사사기 14장', E'삼손의 이야기는 하나님께서 특별한 목적으로 세우신 한 사람이 어떻게 그 부르심에서 멀어져 가는지를 보여줍니다. 나실인으로 태어나 이스라엘을 블레셋의 압제에서 구원하도록 부르심을 받은 삼손이 딤나에서 블레셋 여인을 보고 그녀와 결혼하기를 원합니다. 부모의 만류에도 불구하고 자신의 뜻을 굽히지 않는 삼손의 모습은 하나님의 백성이 이방과 구별되어야 한다는 율법의 가르침과는 거리가 멉니다.\n\n그런데 성경은 이 일이 "여호와께로부터 나온 것"이라고 기록합니다. 하나님께서는 삼손의 연약함마저도 블레셋을 치시는 도구로 사용하신다는 의미입니다. 딤나로 가는 길에 사자를 맨손으로 찢는 삼손의 엄청난 힘은 여호와의 영이 임한 결과였습니다. 그러나 삼손은 돌아오는 길에 사자의 주검에서 꿀을 떠먹음으로써 나실인이 시체를 가까이해서는 안 된다는 규례를 어깁니다. 더욱이 그 꿀을 부모에게도 나누어 주면서 출처를 숨기는 모습은 그의 영적 둔감함을 드러냅니다.\n\n결혼 잔치에서 벌어진 수수께끼 사건은 삼손의 성품을 더욱 선명하게 보여줍니다. 자신의 비밀을 아내에게조차 지키려 했지만, 결국 그녀의 끈질긴 요구에 굴복합니다. 블레셋 사람들이 부정한 방법으로 수수께끼를 풀자 분노한 삼손은 아스글론에서 삼십 명을 죽이고 그들의 옷을 빼앗아 내기에서 진 빚을 갚습니다. 여호와의 영이 그에게 임했다고 기록되어 있지만, 이는 하나님의 큰 계획 안에서 블레셋을 심판하시는 도구로 쓰임 받은 것이지 삼손의 행동이 온전히 의로웠다는 뜻은 아닙니다.\n\n삼손의 첫 결혼이 파경으로 끝나는 이 이야기는 하나님의 부르심을 받은 자가 어떻게 살아야 하는지를 역설적으로 가르쳐 줍니다. 놀라운 은사와 능력을 받았음에도 자기 욕망을 절제하지 못하고 하나님의 규례를 가볍게 여기는 삶은 결국 관계의 파괴와 더 큰 비극으로 이어집니다.', E'오늘의 핵심\n나실인으로 부르심을 받은 삼손이 자신의 욕망을 따라 행동하며 하나님의 규례를 어기는 모습은, 은사와 능력이 있어도 순종 없는 삶은 온전한 열매를 맺을 수 없음을 보여줍니다.\n\n묵상 질문\n1. 하나님께서 주신 은사와 능력을 자기 욕망을 위해 사용한 적은 없나요?\n2. 작은 불순종이 큰 실패로 이어질 수 있다는 것을 어떻게 경계할 수 있을까요?\n3. 하나님의 부르심에 합당하게 살기 위해 오늘 내가 절제해야 할 것은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-03', E'나실인 삼손 (사사기 15장)', E'사사기 15장', E'삼손의 개인적 분노가 블레셋과의 전면적인 충돌로 확대되는 모습을 보여주는 본문입니다. 아내를 빼앗긴 삼손이 여우 삼백 마리의 꼬리에 홰를 달아 블레셋의 곡식밭을 태우는 보복은 한 개인의 원한이 민족 간의 갈등으로 번지는 과정을 생생히 보여줍니다. 이에 대한 블레셋의 보복으로 삼손의 아내와 장인이 불에 타 죽자, 삼손은 더 큰 살육으로 맞서며 악순환의 고리는 계속 이어집니다.\n\n유다 백성들이 삼손을 블레셋에 넘기려 했던 장면은 당시 이스라엘의 영적 상태를 적나라하게 드러냅니다. 하나님께서 세우신 사사를 동족이 결박하여 원수에게 넘기려 한 것은, 그들이 블레셋의 지배를 당연하게 받아들이고 있었음을 보여줍니다. "너는 블레셋 사람이 우리를 다스리는 줄을 알지 못하느냐"(삿 15:11)라는 유다 사람들의 말에는 하나님의 백성으로서의 정체성을 잃어버린 비극이 담겨 있습니다.\n\n그러나 하나님께서는 여전히 삼손과 함께하십니다. 여호와의 영이 삼손에게 임하시자 결박이 풀리고, 나귀 턱뼈 하나로 천 명을 물리치는 놀라운 일이 일어납니다. 더욱 의미심장한 것은 승리 후에 나타난 삼손의 연약함입니다. 목마름으로 죽을 지경에 이른 삼손의 부르짖음에 하나님께서는 바위를 터뜨려 샘물을 주십니다. 이는 삼손의 힘이 자신에게서 나온 것이 아니라 전적으로 하나님의 은혜임을 일깨워주는 장면입니다.\n\n삼손이 20년간 사사로 있었다는 기록은 하나님께서 불완전한 사람도 사용하신다는 진리를 보여줍니다. 개인적 감정에 휘둘리고 나실인의 사명을 온전히 감당하지 못했음에도, 하나님께서는 삼손을 통해 이스라엘을 블레셋의 압제에서 지키셨습니다. 이는 연약한 우리도 하나님의 도구로 쓰임받을 수 있다는 소망의 메시지입니다.', E'오늘의 핵심\n개인적 분노로 시작된 삼손의 보복이 민족 간 갈등으로 번져가는 가운데서도, 하나님께서는 불완전한 삼손을 통해 이스라엘을 지키시며 당신의 구원 계획을 이루어 가십니다.\n\n묵상 질문\n1. 개인적인 감정이 더 큰 갈등으로 번지는 것을 경험한 적이 있나요? 어떻게 하나님의 지혜로 해결할 수 있을까요?\n2. 유다 백성들처럼 세상의 지배를 당연하게 받아들이며 살고 있는 영역은 없나요?\n3. 나의 연약함 속에서도 함께하시는 하나님의 은혜를 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-05', E'나실인 삼손 (사사기 16장)', E'사사기 16장', E'나실인으로 부름받아 이스라엘의 사사가 된 삼손의 마지막은 비극적입니다. 가사의 기생에게 들어간 삼손은 블레셋 사람들의 매복을 가볍게 벗어나며 성문을 뽑아 헤브론 산꼭대기까지 메고 가는 초인적인 힘을 보여줍니다. 그러나 이는 하나님께서 주신 능력을 자신의 욕망을 위해 사용하는 모습이었습니다.\n\n소렉 골짜기의 들릴라를 사랑하게 된 삼손은 더 깊은 함정에 빠져듭니다. 블레셋 방백들이 거액의 은을 약속하며 들릴라를 매수하자, 그녀는 끈질기게 삼손의 힘의 비밀을 캐묻습니다. 삼손은 세 번이나 거짓말로 둘러대지만, 날마다 재촉하는 들릴라의 조름에 결국 "내가 모태에서부터 하나님의 나실인이 되었음이라"는 진실을 털어놓고 맙니다. 나실인의 서원, 곧 하나님과의 거룩한 언약이 이방 여인과의 사랑 앞에서 무너진 것입니다.\n\n머리카락이 잘린 삼손에게서 하나님께서 떠나셨고, 그는 블레셋 사람들에게 잡혀 두 눈이 뽑힌 채 가사의 감옥에서 맷돌을 돌리는 신세가 됩니다. 다곤 신전에서 블레셋 사람들의 구경거리가 된 삼손은 마지막으로 하나님께 부르짖습니다. "이번만 나를 강하게 하사 나의 두 눈을 뺀 블레셋 사람에게 원수를 단번에 갚게 하옵소서"(삿 16:28). 하나님께서는 이 간구를 들으시고 마지막 힘을 허락하십니다. 신전 기둥을 무너뜨려 삼천 명의 블레셋 사람과 함께 죽은 삼손의 최후는, 개인적 복수심으로 생을 마감한 안타까운 사사의 모습을 보여줍니다.\n\n이십 년간 이스라엘의 사사였던 삼손의 이야기는 하나님의 부르심과 은사가 있어도 거룩함을 잃으면 그 사명을 온전히 감당할 수 없음을 가르쳐줍니다. 하나님께서 주신 놀라운 능력도 하나님과의 관계가 무너지면 결국 자기 파멸의 도구가 될 수 있음을 경고하고 있습니다.', E'오늘의 핵심\n나실인의 서원을 저버리고 세상의 유혹에 넘어간 삼손의 비극적 최후는 하나님과의 거룩한 관계를 지키는 것이 얼마나 중요한지 보여줍니다.\n\n묵상 질문\n1. 삼손이 들릴라에게 비밀을 털어놓게 된 과정에서 내 삶의 어떤 모습이 보이나요?\n2. 하나님께서 내게 주신 은사와 능력을 나는 무엇을 위해 사용하고 있나요?\n3. 거룩함을 잃지 않기 위해 오늘 내가 경계해야 할 유혹은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-06', E'기초가 무너진 사회 (사사기 17장)', E'사사기 17장', E'에브라임 산지에 사는 미가의 이야기는 사사 시대 이스라엘의 영적 타락이 얼마나 심각했는지를 생생하게 보여줍니다. 미가는 어머니의 은 천백을 훔쳤다가 저주가 두려워 되돌려주는데, 놀랍게도 어머니는 그 은으로 우상을 만들어 아들에게 줍니다. 더욱 충격적인 것은 어머니가 이 우상 제작을 "여호와께 거룩히 드리노라"고 표현한다는 점입니다. 하나님의 이름으로 우상을 만드는 이 모순된 행위는 당시 백성들이 참된 신앙을 완전히 잃어버렸음을 보여줍니다.\n\n미가는 개인 신당을 만들고 에봇과 드라빔까지 제작합니다. 심지어 자기 아들을 제사장으로 세우는데, 이는 하나님께서 오직 레위 지파 아론의 후손에게만 허락하신 제사장직을 함부로 침범하는 행위였습니다. 그런데 유다 베들레헴에서 온 한 레위인이 생계를 위해 떠돌다가 미가의 집에 이르자, 미가는 그를 개인 제사장으로 고용합니다. 레위인은 하나님의 성소가 아닌 우상이 있는 개인 신당에서 제사장 노릇을 하는 것을 주저하지 않았습니다.\n\n"이제 여호와께서 내게 복 주실 줄을 아노라"(삿 17:13)라는 미가의 확신은 당시 신앙의 왜곡을 극명하게 드러냅니다. 그는 레위인을 고용했으니 자동으로 복을 받을 것이라 믿었습니다. 하나님과의 인격적 관계나 말씀에 대한 순종은 없고, 종교적 형식만 갖추면 복을 보장받는다는 미신적 사고가 지배하고 있었던 것입니다. 사사기는 이 모든 혼란의 원인을 "그 때에는 이스라엘에 왕이 없었으므로 사람마다 자기 소견에 옳은 대로 행하였더라"고 진단합니다. 하나님의 말씀이 기준이 되지 못할 때, 신앙은 이토록 변질되고 맙니다.', E'오늘의 핵심\n하나님의 이름으로 우상을 섬기고, 제사장직을 돈으로 사고파는 미가의 이야기는 말씀을 떠난 신앙이 얼마나 위험한지를 경고합니다.\n\n묵상 질문\n1. 내 신앙생활에서 하나님의 말씀보다 개인적 소견이나 편의를 앞세우는 부분은 없나요?\n2. 종교적 형식만 갖추면 복을 받는다는 기복적 신앙에서 벗어나려면 어떻게 해야 할까요?\n3. 오늘날 우리가 하나님의 이름으로 행하지만 실제로는 우상숭배가 될 수 있는 것들은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-07', E'기초가 무너진 사회 (사사기 18장)', E'사사기 18장', E'단 지파는 이스라엘 지파 중에서 유일하게 아직 기업을 제대로 분배받지 못한 상태였습니다. 원래 그들에게 할당된 땅은 블레셋의 위협으로 정착하기 어려웠기에, 새로운 터전을 찾아 나선 것입니다. 그들이 파견한 정탐꾼들은 에브라임 산지 미가의 집에서 우연히 그 레위인 제사장을 만나게 됩니다. 여기서 주목할 점은 이들이 제사장에게 하나님의 뜻을 묻는 것처럼 보이지만, 실제로는 이미 결정된 일에 대한 형식적인 확인에 불과했다는 것입니다.\n\n정탐꾼들이 발견한 라이스는 평화롭고 부유한 도시였습니다. 시돈과 멀리 떨어져 있고 다른 도시와도 교류가 없어 방비가 허술했습니다. 단 지파는 이를 하나님이 주신 기회로 여기며 육백 명의 무장한 군사를 이끌고 원정을 떠납니다. 가는 길에 다시 미가의 집에 들러 우상들과 제사장을 탈취합니다. 제사장은 한 집안의 제사장보다 한 지파의 제사장이 되는 것을 더 영광스럽게 여겨 기꺼이 그들을 따라갑니다.\n\n단 지파의 이야기는 사사 시대의 영적 혼돈을 적나라하게 보여줍니다. 하나님의 인도하심을 구하는 것처럼 보이지만 실은 자신들의 욕망을 정당화하는 수단으로 신앙을 이용합니다. 무력으로 평화로운 도시를 점령하고, 우상을 세워 섬기면서도 이를 하나님의 축복으로 여깁니다. 특히 "하나님의 집이 실로에 있을 동안에"(삼상 18:31)라는 마지막 구절은 참된 성소가 존재함에도 불구하고 우상 숭배가 계속되었음을 지적합니다. 이는 외형적인 종교 행위는 있으나 진정한 하나님과의 관계는 상실된 시대의 비극을 보여줍니다.', E'오늘의 핵심\n단 지파의 이야기는 하나님의 이름으로 포장된 인간의 욕망과 폭력, 그리고 참된 예배를 잃어버린 시대의 영적 타락상을 보여줍니다.\n\n묵상 질문\n1. 내가 하나님의 뜻이라고 여기는 것들 중에 실은 나의 욕망을 정당화하는 것은 없을까요?\n2. 참된 예배의 자리인 ''실로''를 외면하고 편의적인 신앙을 추구하고 있지는 않나요?\n3. 오늘날 교회 공동체 안에서 힘의 논리가 신앙의 원리를 대체하는 모습이 있다면 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-08', E'예루살렘의 죄악과 심판 (에스겔 8장)', E'에스겔 8장', E'포로로 잡혀간 지 여섯째 해 여섯째 달 초닷새, 에스겔이 자신의 집에서 유다 장로들과 함께 앉아 있을 때 하나님의 권능이 그에게 임했습니다. 하나님께서는 환상 중에 에스겔을 예루살렘 성전으로 데려가셔서 그곳에서 벌어지고 있는 충격적인 광경을 보여주셨습니다. 이 환상은 예루살렘 성전의 영적 타락이 얼마나 심각한 지경에 이르렀는지를 생생하게 드러내 주고 있습니다.\n\n성전 북문 입구에는 ''질투의 우상''이 세워져 있었습니다. 이것은 하나님의 질투를 불러일으키는 우상으로, 성전 안에 이방신의 형상이 버젓이 자리 잡고 있었던 것입니다. 더 깊이 들어가자 칠십 명의 장로들이 은밀한 방에서 벽에 그려진 각종 우상들에게 분향하며 예배하고 있었습니다. 그들은 "여호와께서 우리를 보지 아니하시며 여호와께서 이 땅을 버리셨다"(겔 8:12)고 말하며 자신들의 우상숭배를 정당화했습니다. 하나님께서 보지 않으신다는 그들의 착각이 얼마나 어리석은 것인지, 바로 그 순간 하나님께서는 에스겔을 통해 그들의 은밀한 죄악을 낱낱이 보고 계셨습니다.\n\n성전 북문에서는 여인들이 바벨론의 풍요신 담무스를 위해 애곡하고 있었고, 성전 안뜰에서는 스물다섯 명의 제사장들이 하나님의 성전을 등지고 동쪽 태양을 향해 절하고 있었습니다. 하나님을 섬겨야 할 성전이 온갖 우상숭배의 온상이 되어 있었던 것입니다. 이러한 영적 타락은 단순히 종교적 의식의 문제가 아니라 하나님과의 언약 관계를 완전히 파기하는 배신 행위였습니다. 하나님께서는 이 모든 가증한 일들을 보시고 진노하셨으며, 더 이상 긍휼을 베풀지 않으시겠다고 선언하셨습니다. 성전은 하나님의 임재의 처소였지만, 백성들의 우상숭배로 인해 하나님께서는 그곳을 떠나실 수밖에 없으셨습니다.', E'오늘의 핵심\n하나님께서는 에스겔에게 예루살렘 성전에서 은밀히 행해지는 우상숭배의 실상을 보여주심으로써, 심판이 불가피함을 깨닫게 하셨습니다. 하나님의 성전이 우상의 전으로 변질된 것은 영적 타락의 극치를 보여줍니다.\n\n묵상 질문\n1. 내 삶에서 하나님보다 더 중요하게 여기는 ''질투의 우상''은 무엇인가요?\n2. "하나님이 보지 않으신다"는 착각 속에서 은밀히 행하는 일이 있다면 무엇일까요?\n3. 하나님의 임재가 떠나가실 만큼 심각한 영적 문제가 내 안에 있지는 않은가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-09', E'예루살렘의 죄악과 심판 (에스겔 9장)', E'에스겔 9장', E'하나님의 영광이 성전을 떠나기 직전, 예루살렘에 대한 최후의 심판이 시작됩니다. 에스겔이 본 환상 속에서 하나님은 여섯 명의 심판 집행자를 부르시는데, 그들은 각자 손에 죽이는 무기를 들고 있었습니다. 그중 한 사람은 가는 베 옷을 입고 허리에 서기관의 먹 그릇을 차고 있었는데, 이는 특별한 표식을 기록하기 위한 준비였습니다.\n\n하나님께서는 먼저 베 옷을 입은 사람에게 예루살렘 성읍을 순행하며 "그 가운데에서 행하는 모든 가증한 일로 말미암아 탄식하며 우는 자의 이마에 표를 그리라"(겔 9:4)고 명령하십니다. 이 표는 심판 가운데서도 구원받을 자들을 구별하는 인장이었습니다. 죄악으로 가득한 도성에서도 여전히 하나님의 공의를 갈망하며 탄식하는 남은 자들이 있었던 것입니다.\n\n표시가 끝난 후, 나머지 다섯 명의 집행자들에게는 무서운 명령이 내려집니다. 늙은 자와 젊은 자, 처녀와 어린이와 여자를 가리지 않고 모두 죽이되, 오직 이마에 표 있는 자에게는 가까이하지 말라는 것이었습니다. 더욱 충격적인 것은 이 심판이 하나님의 성소에서부터 시작되었다는 점입니다. 성전 앞의 늙은 지도자들부터 심판이 시작된 것은, 하나님께 가장 가까이 있으면서도 가장 큰 책임을 저버린 이들에 대한 엄중한 경고였습니다.\n\n홀로 남겨진 에스겔은 엎드려 부르짖으며 이스라엘의 남은 자마저 멸하시려는지 간구합니다. 그러나 하나님의 대답은 단호했습니다. 이스라엘과 유다의 죄악이 너무나 무거워 땅에는 피가 가득하고 성읍에는 불법이 찼으며, 백성들은 "여호와께서 이 땅을 버리셨으며 여호와께서 보지 아니하신다"고 말하며 더욱 악을 행했다는 것입니다. 하나님의 오래 참으심을 무시하고 그분의 임재를 부인한 결과가 이렇게 무서운 심판으로 나타난 것입니다.\n\n이 환상은 하나님의 심판이 무차별적이지 않음을 보여줍니다. 죄악 가운데서도 의를 갈망하며 탄식하는 자들을 하나님은 기억하시고 보호하십니다. 동시에 하나님과 가장 가까운 곳에서 섬기는 자들이 더 큰 책임을 지고 있음을 엄중히 경고합니다.', E'오늘의 핵심\n하나님은 심판 가운데서도 죄악을 슬퍼하며 탄식하는 자들을 구별하여 보호하시지만, 성전에서 섬기면서도 불의를 행한 자들부터 엄격히 심판하십니다.\n\n묵상 질문\n1. 내 주변의 불의와 죄악을 보며 진정으로 탄식하고 있나요, 아니면 무감각해졌나요?\n2. 하나님과 가까이 있다고 생각하면서도 놓치고 있는 나의 책임은 무엇일까요?\n3. 하나님의 임재를 의심하거나 무시하며 살아가고 있지는 않은가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-10', E'예루살렘의 죄악과 심판 (에스겔 10장)', E'에스겔 10장', E'에스겔이 다시 보게 된 환상은 그발 강가에서 보았던 그 영광스러운 광경이었습니다. 그룹들과 바퀴, 그리고 그 위에 계신 하나님의 보좌가 여전히 그 위엄을 드러내고 있었지만, 이번에는 전혀 다른 목적으로 나타났습니다. 가는 베 옷을 입은 천사에게 하나님께서 명하신 것은 그룹들 사이에 있는 숯불을 가져다가 예루살렘 성읍 위에 흩으라는 것이었습니다. 이는 곧 다가올 심판의 불길을 예고하는 상징적 행위였습니다.\n\n그런데 더욱 충격적인 장면이 이어집니다. 여호와의 영광이 성전 문지방을 떠나 그룹들 위로 옮겨가고, 마침내 성전의 동문으로 이동하는 모습이 상세히 묘사됩니다. 이스라엘의 역사에서 성전은 하나님의 임재를 상징하는 가장 거룩한 장소였습니다. 솔로몬이 성전을 봉헌할 때 구름이 가득 차 제사장들이 서서 섬기지 못할 정도로 하나님의 영광이 충만했던 바로 그 성전에서, 이제는 정반대의 일이 일어나고 있었습니다. 하나님의 영광이 단계적으로 성전을 떠나가는 것입니다.\n\n에스겔은 이 장면을 목격하면서 그룹들의 모습을 더욱 자세히 관찰합니다. 네 얼굴을 가진 그룹들과 눈이 가득한 바퀴들, 그리고 생물의 영이 바퀴 가운데 있어 일체가 되어 움직이는 모습은 하나님의 절대 주권과 전지전능하심을 보여줍니다. 그러나 이 영광스러운 존재들이 이제는 심판의 도구가 되어 예루살렘을 떠날 준비를 하고 있었습니다. 백성들의 거듭된 우상숭배와 불순종으로 인해 하나님께서는 더 이상 그들 가운데 거하실 수 없었던 것입니다. "여호와의 영광이 성전 문지방을 떠나서 그룹들 위에 머무르니"(겔 10:18)라는 구절은 이스라엘 역사상 가장 비극적인 순간을 담담히 전해주고 있습니다.', E'오늘의 핵심\n하나님의 영광이 백성들의 죄악으로 인해 성전을 떠나가는 비극적 순간을 통해, 거룩함을 잃어버린 종교와 형식적 예배의 무의미함을 보여줍니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 임재가 희미해진 영역은 어디인가요?\n2. 형식적인 신앙생활로 인해 놓치고 있는 하나님의 영광은 무엇일까요?\n3. 하나님께서 떠나가시기 전에 내가 회복해야 할 거룩함은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-12', E'예루살렘의 죄악과 심판 (에스겔 11장)', E'에스겔 11장', E'사로잡혀 온 지도자들이 바벨론에서 절망에 빠져 있을 때, 에스겔은 하나님의 영에 이끌려 환상 중에 예루살렘으로 옮겨집니다. 성전 동문에서 목격한 장면은 충격적이었습니다. 야아사냐와 블라댜를 비롯한 25명의 지도자들이 모여 있었는데, 이들은 백성을 잘못된 길로 인도하는 거짓 평안의 메시지를 전하고 있었습니다. "집 건축할 때가 가깝지 아니한즉 이 성읍은 가마가 되고 우리는 고기가 된다"(겔 11:3)라는 그들의 말은 예루살렘이 가마처럼 안전하며 자신들은 그 안에서 보호받는 고기와 같다는 자만심을 드러냅니다.\n\n하나님께서는 이러한 거짓 안전감에 대해 신랄한 심판의 말씀을 선포하십니다. 아이러니하게도 그들이 죽인 시체들이 진짜 ''고기''가 되고, 정작 그들은 성읍 밖으로 끌려나가 이방인의 손에 심판받게 될 것입니다. 에스겔이 예언하던 중 블라댜가 갑작스레 죽는 충격적인 사건은 하나님의 심판이 얼마나 임박했는지를 생생하게 보여줍니다.\n\n그러나 하나님의 메시지는 심판으로만 끝나지 않습니다. 예루살렘에 남은 자들이 포로로 잡혀간 동포들을 향해 "여호와에게서 멀리 떠나라"고 조롱하지만, 오히려 하나님께서는 흩어진 백성들과 함께하시며 그들에게 ''잠깐 성소''가 되어주신다고 약속하십니다. 더 나아가 그들을 다시 모으시고, 돌같이 굳은 마음을 제거하여 살처럼 부드러운 새 마음을 주시겠다는 놀라운 회복의 약속을 주십니다. 이는 단순한 귀환이 아니라 내면의 근본적인 변화, 곧 새로운 언약 관계의 시작을 의미합니다.\n\n환상이 끝나고 에스겔은 다시 바벨론의 포로들에게로 돌아옵니다. 그가 전해야 할 메시지는 명확했습니다. 예루살렘의 멸망은 피할 수 없지만, 하나님께서는 흩어진 백성들 가운데 계시며 그들을 통해 새로운 미래를 준비하고 계신다는 것입니다.', E'오늘의 핵심\n거짓 평안에 취한 예루살렘 지도자들에게는 심판이, 흩어진 포로들에게는 ''새 마음''의 약속이 주어집니다. 하나님은 심판 가운데서도 회복의 희망을 준비하십니다.\n\n묵상 질문\n1. 내가 의지하고 있는 ''거짓 안전감''은 무엇이며, 하나님은 나에게 어떤 참된 평안을 주시나요?\n2. ''돌 같은 마음''에서 ''살처럼 부드러운 마음''으로의 변화를 위해 내가 버려야 할 것은 무엇일까요?\n3. 하나님께서 어려운 상황 속에서도 나의 ''성소''가 되어주신다는 약속이 오늘 나에게 어떤 위로를 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-13', E'원칙 없는 문제 해결', E'사사기 19장', E'사사기 19~21장의 사건은 거룩한 사회를 세우기 위한 기초 제도가 무너지고 이스라엘의 죄악이 갈수록 커져감을 보여줍니다. 에브라임 산지 출신인 한 레위인에게 일어난 사건이 이스라엘 전체로 확대되고, 그 결과 베냐민 지파가 거의 멸망으로 치닫게 되었습니다. 소돔과 고모라의 죄악(창 19:1~11)을 몇 백 년이 지난 지금 반복하고 있는 것입니다. 삶의 방식이 저급했던 기브아의 불량배들, 복수심에 불타 사명을 잊어버린 레위인, 율법의 내용(신 19:11~13)을 무시하고 불량배들을 내놓지 않은 베냐민 지파 사람들로 인해 민족 공동체인 이스라엘이 동족끼리 살육하는 참상을 빚어낸 것입니다.\n사사기의 마지막 장에 나오는 전쟁 사후처리는 더 당황스럽습니다. 전쟁에서 많은 사람이 죽고 베냐민 지파가 사라질 위기에 처한 것을 알게 된 이스라엘 백성은 어떻게든 열두 지파의 명맥을 유지하고자 옳지 못한 방법으로 베냐민 지파의 신부가 될 사람들을 구합니다. 하나님의 말씀과 상관없이 각자 자기 소견에 옳은 대로 살았던 사사 시대를 바라보시는 하나님의 마음을 생각하면, 안타깝고 참담하기 그지없습니다.', E'오늘의 핵심\n한 레위인의 첩의 죽음에서 시작되어 온 이스라엘을 전쟁으로 몰아간 사건은 사사 시대의 혼란상을 대표적으로 보여줍니다.\n\n묵상 질문\n하나님은 왜 이스라엘이 원칙과 율법을 버렸을 때 심판하셨을까요?\n내가 신앙의 원칙을 편의대로 타협하고 있지는 않은지 돌아보고 있나요?\n이 시대의 부패와 혼란 속에서 나는 어떻게 거룩함을 지킬 결심을 하겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-14', E'아름다운 율법의 구현', E'룻기 4장', E'기근 어두운 사사 시대에 피어난 아름다운 들꽃 같은 이야기입니다. 베들레헴 땅에 살던 엘리멜렉 가족은 흉년을 피해 모압 땅으로 이주하고, 아들들은 모압 여인과 결혼하였습니다. 하지만 얼마 못 가 남편도 잃고 두 아들도 잃은 나오미는 결국 하나님을 찾습니다. 고향 베들레헴으로 돌아가기로 결심한 나오미는 며느리들에게 재혼의 길을 터주고자 각자의 친정으로 돌아가라고 권합니다. 오르바는 친정으로 돌아가지만 룻은 나오미 곁을 지킵니다. 베들레헴에 도착한 룻은 자신과 어머니의 양식거리를 찾아 다른 사람들의 밭으로 나서고, 우연히 보아스의 밭에 다다릅니다. 하나님의 인도하심과 은혜였습니다.\n보아스와 그 밭의 일꾼들이 하나님의 이름으로 인사를 주고받는 모습은 그 당시가 사사 시대임을 감안하면 범상치 않은 일입니다. 또한 보아스는 이방 여인인 룻을 배려하고 결국 룻을 자기 아내로 맞이하게 됩니다. 사사 시대임에도 불구하고 하나님의 말씀을 실천했던 보아스의 삶은 인간이 하나님의 율법을 준행하여 사는 것이 얼마나 복되고 아름다운지를 보여주는 샘플입니다.', E'오늘의 핵심\n사사 시대 베들레헴 마을에서 있었던 룻기 이야기는 하나님의 율법이 실제 삶의 현장에서 구현되는 아름다운 이야기입니다.\n\n묵상 질문\n하나님은 어떤 상황에서도 우리를 버리지 않으신다고 믿으시나요?\n룻처럼 낯선 곳에서 신실하게 살아가는 것이 나에게 어떤 의미인가요?\n지금 내 삶에서 하나님의 인도하심을 경험하려면 어떻게 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-15', E'하나님을 배역하는 거짓 선지자들 (에스겔 12장)', E'에스겔 12장', E'하나님께서는 반역하는 백성에게 말씀만이 아닌 행동으로도 말씀하십니다. 에스겔에게 포로의 행장을 꾸리고 낮에는 그것을 밖으로 내놓고, 저물어서는 성벽을 뚫고 어깨에 메고 나가라고 명령하십니다. 이 모든 상징적 행동은 곧 예루살렘에 임할 심판을 미리 보여주는 것이었습니다. 시드기야 왕이 밤중에 성벽을 뚫고 도망가다가 바벨론 군대에게 붙잡혀 눈이 뽑힌 채 바벨론으로 끌려갈 운명을 예고하는 것입니다.\n\n이스라엘 백성은 볼 눈이 있어도 보지 않고 들을 귀가 있어도 듣지 않는 반역하는 족속이었습니다. 그들은 "날이 더디고 모든 묵시가 사라지리라"며 하나님의 예언을 조롱했습니다. 심판의 경고가 당장 이루어지지 않자 하나님의 말씀을 무시하고 안일하게 살아갔던 것입니다. 그러나 하나님은 분명히 선포하십니다. 허탄한 묵시와 아첨하는 복술이 사라지고, 하나님의 말씀은 더 이상 지체되지 않고 반드시 이루어질 것이라고 말입니다.\n\n하나님은 심판 가운데서도 소수의 남은 자를 보존하실 계획을 갖고 계셨습니다. 칼과 기근과 전염병에서 벗어난 이들은 이방인 가운데서 자신들의 가증한 일을 자백하며 하나님을 증거하는 도구가 될 것입니다. 이것이 심판 너머에 있는 하나님의 은혜였습니다. 반역하는 백성을 향한 하나님의 마음은 단순한 진노가 아니라, 그들이 돌이켜 하나님을 알기를 간절히 바라는 아버지의 마음이었습니다.', E'오늘의 핵심\n하나님은 반역하는 백성에게 에스겔의 상징적 행동을 통해 임박한 심판을 보여주시며, 그분의 말씀은 반드시 이루어짐을 선포하십니다.\n\n묵상 질문\n1. 하나님의 경고를 듣고도 "아직 시간이 있다"며 미루고 있는 것은 무엇인가요?\n2. 내 삶에서 하나님의 말씀보다 세상의 소리에 더 귀 기울이고 있지는 않나요?\n3. 심판 중에도 남은 자를 두시는 하나님의 은혜가 오늘 나에게 주는 위로는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-16', E'하나님을 배역하는 거짓 선지자들 (에스겔 13장)', E'에스겔 13장', E'하나님의 말씀이 에스겔을 통해 거짓 선지자들에게 향합니다. 당시 이스라엘에는 하나님의 부르심 없이 자기 마음대로 예언하는 자들이 많았습니다. 그들은 "여호와께서 말씀하셨다"고 외쳤지만, 실제로는 자신의 생각과 욕망을 하나님의 이름으로 포장했을 뿐이었습니다. \n\n하나님께서는 이들을 "황무지에 있는 여우"에 비유하십니다. 여우가 폐허 속을 배회하며 먹이를 찾듯이, 거짓 선지자들은 백성의 절망과 혼란을 이용해 자신의 이익을 추구했습니다. 그들은 성벽의 무너진 틈을 막아 백성을 보호해야 할 책임이 있었지만, 오히려 거짓 평안의 메시지로 백성을 더 큰 위험에 빠뜨렸습니다.\n\n특히 하나님께서는 이들의 거짓 예언을 "회칠한 담"에 비유하십니다. 겉으로는 깨끗하고 견고해 보이지만 실제로는 금방 무너질 수밖에 없는 담입니다. 거짓 선지자들은 "평강이 없으나 평강이 있다"고 선포하며 백성을 안심시켰지만, 하나님의 심판이 폭풍우처럼 몰아치면 그들의 거짓말은 모두 드러나고 말 것입니다.\n\n더욱 심각한 것은 여선지자들의 행태였습니다. 그들은 부적과 수건으로 사람들의 영혼을 사냥했습니다. "두어 움큼 보리와 두어 조각 떡"이라는 보잘것없는 대가를 위해 생명과 죽음에 관한 거짓말을 퍼뜨렸습니다. 의인의 마음을 상하게 하고 악인이 회개하지 못하도록 막았습니다.\n\n그러나 하나님께서는 이 모든 거짓을 끝내실 것이라고 선언하십니다. 거짓 선지자들은 하나님 백성의 공회에서 제외되고, 이스라엘의 호적에서 지워지며, 약속의 땅에도 들어가지 못할 것입니다. 하나님께서는 그분의 백성을 거짓 선지자들의 손에서 건져내실 것입니다. 이 모든 심판을 통해 하나님께서 궁극적으로 원하시는 것은 단 하나, "내가 여호와인 줄을 너희가 알리라"는 것입니다.', E'오늘의 핵심\n거짓 선지자들은 하나님의 이름으로 자신의 욕망을 포장하며 백성을 미혹시켰지만, 하나님께서는 그들의 거짓을 폭로하시고 참된 말씀으로 백성을 회복시키실 것입니다.\n\n묵상 질문\n1. 오늘날 우리 주변에서 "평안하다, 평안하다" 외치는 거짓된 목소리는 무엇일까요?\n2. 내가 듣고 싶은 말과 하나님께서 주시는 참된 말씀을 어떻게 분별할 수 있을까요?\n3. 하나님의 백성으로서 무너진 곳을 막아서는 중보자의 역할을 감당하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-17', E'하나님을 배역하는 거짓 선지자들 (에스겔 14장)', E'에스겔 14장', E'이스라엘 장로들이 에스겔을 찾아왔지만, 하나님께서는 그들의 마음속을 꿰뚫어 보고 계셨습니다. 겉으로는 하나님의 뜻을 구하러 온 듯했으나, 그들의 마음에는 이미 우상이 자리 잡고 있었습니다. "이 사람들이 자기 우상을 마음에 들이며 죄악의 걸림돌을 자기 앞에 두었으니"(겔 14:3)라는 하나님의 말씀은 그들의 이중적인 모습을 정확히 지적합니다. \n\n하나님께서는 우상을 마음에 품은 채로 하나님께 나아오는 자들에게 그들이 섬기는 우상의 수효대로 보응하시겠다고 선언하십니다. 이는 단순한 형벌의 선언이 아니라, 그들이 선택한 길의 결과를 스스로 거두게 하시는 하나님의 공의로운 심판입니다. 그럼에도 하나님의 마음은 여전히 당신의 백성을 향하고 있었습니다. 심판의 목적은 "이스라엘 족속이 다시는 미혹되어 나를 떠나지 아니하게 하며" 그들을 참된 하나님의 백성으로 회복시키는 데 있었습니다.\n\n특히 주목할 점은 노아, 다니엘, 욥과 같은 의인들이 있다 하더라도 그들의 의로움이 다른 사람을 구원할 수 없다는 엄중한 선언입니다. 각 사람은 자기의 믿음과 행실로 하나님 앞에 서야 합니다. 이는 신앙이 결코 대물림되거나 타인에게 의존할 수 없는 개인적 결단의 문제임을 분명히 보여줍니다. 칼과 기근, 사나운 짐승과 전염병이라는 네 가지 중한 심판이 임할 때, 오직 각자의 공의로만 자기 생명을 건질 수 있다는 말씀은 우리에게 깊은 경각심을 불러일으킵니다.\n\n그러나 하나님의 심판 가운데서도 소망의 빛줄기가 보입니다. 예루살렘에서 피하는 자들이 남아 있을 것이며, 그들을 통해 하나님의 심판이 결코 이유 없이 행해진 것이 아님을 깨닫게 될 것입니다. 하나님의 심판은 파괴가 목적이 아니라 회복을 위한 과정이었던 것입니다.', E'오늘의 핵심\n우상을 마음에 품은 채 하나님께 나아오는 것은 거짓된 신앙이며, 각 사람은 오직 자기의 믿음으로 하나님 앞에 서야 합니다.\n\n묵상 질문\n1. 내 마음속에 하나님보다 더 중요하게 여기는 우상은 없는지 점검해 보셨나요?\n2. 다른 사람의 믿음에 기대지 않고 나만의 진실한 신앙을 갖기 위해 무엇이 필요할까요?\n3. 하나님의 경고와 징계를 통해 회복을 경험한 적이 있다면 나누어 보세요.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-19', E'준비되는 사무엘', E'사무엘상 1장', E'가나안에 정착한 이스라엘 백성이 신앙교육에 실패한 결과로 시대 전체가 약 350여 년 이상 긴 어둠의 터널을 지나야 했습니다. 이어지는 사무엘상은 사사 시대의 어두운 고리를 끊고 시대를 개척한 사무엘, 이스라엘의 초대 왕 사울 그리고 그 뒤를 이어 준비되는 다윗의 이야기입니다.\n어두운 사사 시대의 역사를 광명의 시대로 인도할 한 사람이 준비되고 있습니다. 한나가 하나님의 전에 와서 눈물로 기도하는데, 그 기도의 내용은 "아들을 주시면 내가 그의 평생에 그를 여호와께 드리고 삭도를 그의 머리에 대지 아니하겠나이다"(삼상 1:11)라는 것이었습니다. 한나는 기도하다 구한 대로 아들을 낳았으며, 서원한 대로 그 아들을 하나님께 바칩니다. 한나가 엘리의 아들들에 관한 나쁜 소문을 몰랐을 리 없습니다. 그럼에도 불구하고 한나는 하나님을 향한 믿음을 가지고 엘리에게 아들을 맡긴 것입니다. 이렇게 사무엘은 젖을 떼자마자 부모를 떠나 하나님의 사람으로 준비되기 시작합니다. 그 준비의 내용은 첫째, 엘리를 통한 율법 교육이며, 둘째, 홉니와 비느하스를 반면교사로 삼아 하나님 앞에 더욱 바로 서는 것이었습니다. 그 준비 뒤에는 어머니 한나의 간절한 기도가 있었습니다.', E'오늘의 핵심\n하나님께서는 350여 년이라는 긴 불순종의 흐름을 끊고 시대를 새롭게 개척할 하나님의 사람으로 사무엘을 선택하여 교육하십니다.\n\n묵상 질문\n하나님은 어두운 시대를 바꾸기 위해 한 사람을 준비하시나요?\n한나처럼 눈물의 기도로 준비되어야 할 내 삶의 영역은 무엇일까요?\n하나님 앞에 온전히 드릴 것이 무엇인지 기도해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-20', E'사무엘의 말씀 개혁운동 (사무엘상 4장)', E'사무엘상 4장', E'이스라엘이 블레셋과의 전쟁에서 패배하자 장로들은 하나님의 언약궤를 전쟁터로 가져오기로 결정합니다. 그들은 언약궤가 있으면 승리할 수 있을 것이라 생각했습니다. 하지만 이는 하나님을 주술적인 부적 정도로 여기는 잘못된 신앙이었습니다. 언약궤와 함께 엘리의 두 아들 홉니와 비느하스도 전쟁터에 나갔지만, 결과는 더욱 참혹했습니다. 이스라엘은 삼만 명의 군사를 잃었고, 언약궤마저 빼앗기고 말았습니다. \n\n하나님께서는 타락한 제사장들의 손에 들린 언약궤가 전쟁의 도구로 이용되는 것을 허락하지 않으셨습니다. 오히려 언약궤를 빼앗기게 하심으로써 이스라엘이 의지해야 할 것은 눈에 보이는 궤가 아니라 살아계신 하나님 자신임을 가르치셨습니다. 전쟁터에서 홉니와 비느하스가 죽고, 그 소식을 들은 엘리도 의자에서 뒤로 넘어져 목이 부러져 죽습니다. 사십 년간 이스라엘의 사사였던 엘리의 죽음은 한 시대의 종말을 알리는 신호였습니다.\n\n비느하스의 아내는 하나님의 궤가 빼앗기고 시아버지와 남편이 죽었다는 소식을 듣고 아들을 낳으며 죽어갑니다. 그녀는 아이의 이름을 ''이가봇''이라 지었는데, 이는 "영광이 떠났다"는 뜻입니다. 하나님의 임재를 상징하던 언약궤가 이방인의 손에 넘어간 것은 단순한 전쟁 패배가 아니라 이스라엘에서 하나님의 영광이 떠난 것을 의미했습니다. 부패한 지도자들과 형식적인 신앙으로는 하나님의 영광을 붙잡아 둘 수 없었던 것입니다. 이제 하나님께서는 새로운 시대를 열기 위해 준비하신 사무엘을 통해 이스라엘을 회복시키실 것입니다.', E'오늘의 핵심\n하나님을 도구화하려는 형식적 신앙은 오히려 하나님의 영광이 떠나는 비극을 초래합니다. 참된 회복은 진실한 회개와 하나님께 대한 온전한 신뢰에서 시작됩니다.\n\n묵상 질문\n1. 나는 하나님을 나의 목적을 위한 수단으로 여기고 있지는 않나요?\n2. 내 삶에서 ''이가봇''이라 불릴 만한, 하나님의 영광이 떠난 영역은 어디인가요?\n3. 형식적 신앙에서 벗어나 살아계신 하나님과의 관계를 회복하려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-21', E'사무엘의 말씀 개혁운동 (사무엘상 5장)', E'사무엘상 5장', E'블레셋 사람들이 전쟁에서 승리하고 하나님의 궤를 전리품으로 빼앗아 갔습니다. 그들은 이스라엘의 하나님을 이긴 증거로 여기며, 궤를 자신들의 신 다곤의 신전에 가져다 놓았습니다. 고대 근동의 관습대로 패배한 신의 상징물을 승리한 신의 발 앞에 두어 굴복시킨 것입니다. 그러나 다음날 아침, 아스돗 사람들은 놀라운 광경을 목격합니다. 그들의 신 다곤이 여호와의 궤 앞에 엎드러져 있었던 것입니다. 사람들이 다곤을 다시 세워놓았지만, 그 다음날에는 다곤의 머리와 손목이 잘려 문지방에 떨어져 있고 몸뚱이만 남아 있었습니다. \n\n이것은 단순한 우연이 아니었습니다. 하나님께서는 블레셋의 우상이 참 신이 아님을 분명히 보여주신 것입니다. 더 나아가 하나님의 손이 아스돗과 그 지역에 임하여 독한 종기의 재앙을 내리셨습니다. 블레셋 사람들은 궤를 가드로, 다시 에그론으로 옮겼지만, 가는 곳마다 재앙이 따랐습니다. "온 성읍이 사망의 환난을 당함이라"(삼상 5:11)는 기록은 하나님의 심판이 얼마나 엄중했는지를 보여줍니다. \n\n이 사건은 비록 이스라엘이 전쟁에서 패했고 언약궤를 빼앗겼지만, 하나님의 주권과 능력은 조금도 손상되지 않았음을 증명합니다. 오히려 이방 땅에서도 하나님께서는 자신이 유일한 참 신이심을 나타내셨습니다. 블레셋 사람들이 결국 궤를 돌려보내기로 결정한 것은 그들도 이스라엘 하나님의 능력을 인정할 수밖에 없었기 때문입니다. 하나님께서는 때로 우리의 실패와 좌절의 상황에서도 자신의 영광을 드러내시는 분이십니다.', E'오늘의 핵심\n하나님께서는 블레셋 땅에서 우상 다곤을 무너뜨리고 재앙을 내리심으로써, 비록 이스라엘이 패했어도 여전히 주권자이심을 증명하셨습니다.\n\n묵상 질문\n1. 내 삶의 패배와 실패 속에서도 여전히 일하시는 하나님을 신뢰하고 있나요?\n2. 하나님보다 더 의지하고 있는 내 삶의 ''다곤''은 무엇인가요?\n3. 하나님의 주권을 인정하지 못하게 막는 교만은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-22', E'사무엘의 말씀 개혁운동 (사무엘상 6장)', E'사무엘상 6장', E'블레셋 땅에 머물렀던 언약궤가 일곱 달 만에 이스라엘로 돌아오는 과정을 통해 하나님의 주권과 거룩하심이 드러납니다. 블레셋 사람들은 언약궤로 인한 재앙을 더 이상 견디지 못하고 제사장들과 복술자들을 불러 대책을 논의합니다. 그들의 조언에 따라 블레셋 방백들은 금 독종 다섯 개와 금 쥐 다섯 개를 속건제물로 준비하여 언약궤와 함께 보내기로 합니다. 이는 각 도시를 대표하는 것으로, 그들이 겪은 재앙의 심각성을 인정하는 행위였습니다.\n\n특히 주목할 점은 블레셋 사람들이 애굽의 바로를 언급하며 과거 역사의 교훈을 기억하고 있다는 것입니다. 그들은 멍에를 메어보지 않은 젖 나는 소 두 마리에 수레를 끌게 하여 언약궤를 싣되, 송아지들은 집으로 돌려보냅니다. 이는 어미 소가 본능적으로 송아지에게 돌아가려 할 것이므로, 만약 이스라엘 땅으로 곧장 간다면 그것이 하나님의 역사임을 확인하려는 의도였습니다. 놀랍게도 소들은 "벧세메스 길로 바로 행하여 대로로 가며 갈 때에 울고 좌우로 치우치지 아니하였"(삼상 6:12)습니다. 이는 하나님께서 직접 인도하신 초자연적 사건이었습니다.\n\n벧세메스에 도착한 언약궤를 본 이스라엘 백성들은 기뻐하며 번제와 제사를 드립니다. 그러나 일부 사람들이 호기심으로 언약궤를 들여다본 일로 인해 칠십 명이 죽임을 당하는 비극이 일어납니다. 이 사건은 하나님의 거룩하심을 가볍게 여기면 안 된다는 엄중한 교훈을 줍니다. 결국 벧세메스 사람들은 두려워하며 언약궤를 기럇여아림으로 보내게 됩니다. 하나님은 이방인들에게도, 그리고 자기 백성에게도 동일하게 거룩하신 분이심을 보여주신 것입니다.', E'오늘의 핵심\n하나님은 블레셋 사람들을 통해서도 자신의 주권을 나타내시며, 언약궤를 가볍게 다루는 것을 용납하지 않으심으로 거룩함의 중요성을 가르치십니다.\n\n묵상 질문\n1. 하나님의 임재를 가볍게 여기거나 호기심의 대상으로 삼고 있지는 않나요?\n2. 내 삶에서 하나님의 거룩하심을 더욱 경외해야 할 부분은 무엇인가요?\n3. 하나님께서 나를 인도하시는 초자연적인 손길을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-23', E'사무엘의 말씀 개혁운동 (사무엘상 7장)', E'사무엘상 7장', E'하나님의 궤가 기럇여아림에 머문 이십 년의 세월은 이스라엘 백성에게 깊은 반성과 회복의 시간이었습니다. 그 긴 침묵의 시간 끝에 이스라엘 온 족속이 여호와를 사모하는 놀라운 변화가 일어났습니다. 하나님께서는 준비된 지도자 사무엘을 통해 이들의 갈망에 응답하셨습니다.\n\n사무엘은 백성들에게 진정한 회개의 길을 제시합니다. 단순히 감정적 후회가 아닌, 삶의 구체적인 변화를 요구한 것입니다. 바알과 아스다롯 같은 이방 신들을 제거하고 오직 여호와만을 섬기라는 그의 메시지는 분명했습니다. 이스라엘 백성은 이 말씀에 순종하여 우상들을 제거하고 여호와만을 섬기기 시작했습니다.\n\n미스바에서의 대성회는 이스라엘 역사의 중요한 전환점이 됩니다. 백성들은 물을 길어 여호와 앞에 부으며 자신들의 죄를 철저히 고백했습니다. 종일 금식하며 "우리가 여호와께 범죄하였나이다"(삼상 7:6)라고 고백하는 그들의 모습은 진정한 회개가 무엇인지를 보여줍니다. 바로 이때 블레셋의 위협이 닥쳐왔지만, 하나님께서는 큰 우레로 적을 어지럽게 하시어 이스라엘에게 승리를 주셨습니다.\n\n사무엘이 세운 에벤에셀 돌은 ''도움의 돌''이라는 뜻으로, 하나님의 신실하신 도우심을 기념하는 표석이었습니다. 이후 블레셋은 다시는 이스라엘 지역에 들어오지 못했고, 빼앗겼던 성읍들이 회복되는 은혜가 임했습니다. 사무엘은 계속해서 벧엘과 길갈과 미스바를 순회하며 말씀으로 백성을 가르쳤습니다. 그의 지속적인 말씀 사역은 이스라엘이 하나님께로 돌아온 마음을 계속 지켜가도록 도왔습니다.', E'오늘의 핵심\n이십 년의 침묵 끝에 이스라엘이 여호와를 사모하자, 하나님께서는 사무엘을 통해 참된 회개와 회복의 길로 인도하시고 에벤에셀의 승리를 주셨습니다.\n\n묵상 질문\n1. 내 삶에도 하나님을 진정으로 사모하는 갈급함이 있나요?\n2. 내가 제거해야 할 우상은 무엇이며, 어떻게 구체적으로 회개할 수 있을까요?\n3. 하나님의 도우심을 기억하는 나만의 ''에벤에셀''은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-24', E'길르앗 야베스 사건과 사무엘의 고별사 (사무엘상 11장)', E'사무엘상 11장', E'길르앗 야베스가 암몬의 위협 앞에 놓였을 때, 이스라엘은 아직 통합된 국가의 모습을 갖추지 못한 상태였습니다. 왕으로 기름부음을 받았지만 여전히 고향에서 농사를 짓던 사울에게 절체절명의 소식이 전해집니다. 암몬 왕 나하스가 제시한 조건은 잔인했습니다. 길르앗 야베스 사람들의 오른 눈을 모두 빼겠다는 것은 단순한 신체적 훼손을 넘어 이스라엘 전체를 모욕하려는 의도였습니다. 전사로서의 능력을 상실시키고 평생 치욕의 표시를 남기려 한 것입니다.\n\n야베스의 급박한 전령이 사울의 귀에 들렸을 때, 성경은 "하나님의 영에게 크게 감동되매"(삼상 11:6)라고 기록합니다. 평범한 농부였던 사울이 진정한 왕으로 변화되는 순간이었습니다. 그는 소를 잡아 각을 떠 이스라엘 전역에 보내며 강력한 소집령을 내립니다. 하나님의 영이 사울에게 임하자 그의 리더십도 함께 나타났고, 백성들에게는 여호와를 경외하는 마음이 생겨 한 사람같이 모였습니다.\n\n새벽 기습작전으로 암몬을 완전히 격파한 사울은 이제 명실상부한 이스라엘의 지도자가 되었습니다. 그러나 더욱 주목할 점은 승리 후 사울이 보인 관용입니다. 과거 자신을 반대했던 사람들에 대한 보복을 거부하며 "여호와께서 오늘 이스라엘 중에 구원을 베푸셨음이니라"라고 선언합니다. 승리의 공을 하나님께 돌리는 겸손함과 화합을 추구하는 지혜가 돋보입니다.\n\n길갈에서의 왕위 갱신식은 단순한 재확인이 아니었습니다. 실제적인 군사 지도자로서의 능력을 증명한 사울을 중심으로 이스라엘이 하나의 국가로 결속되는 역사적 전환점이었습니다. 화목제를 드리며 크게 기뻐하는 백성들의 모습은 하나님께서 주신 새로운 시작에 대한 감사와 기대를 보여줍니다.', E'오늘의 핵심\n하나님의 영이 사울에게 임하자 그는 위기에 처한 동족을 구원하는 진정한 지도자로 변화되었고, 이 승리를 통해 이스라엘은 하나의 국가로 결속되기 시작했습니다.\n\n묵상 질문\n1. 내 삶에도 하나님의 영이 임하여 담대한 믿음의 결단을 내려야 할 때가 있었나요?\n2. 승리와 성공의 순간에도 그 영광을 하나님께 돌릴 수 있는 겸손함이 내게 있나요?\n3. 공동체의 위기 앞에서 나는 어떤 역할로 부르심을 받고 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-26', E'길르앗 야베스 사건과 사무엘의 고별사 (사무엘상 12장)', E'사무엘상 12장', E'사무엘의 고별 연설은 이스라엘 역사의 중요한 전환점을 보여줍니다. 지도자로서의 공적 사역을 마무리하며, 사무엘은 먼저 자신의 청렴했던 삶을 백성 앞에 내놓습니다. "내가 누구의 소를 빼앗았느냐 누구의 나귀를 빼앗았느냐"(삼상 12:3)라는 그의 물음에 백성은 한목소리로 그의 정직함을 증언합니다. 이는 단순한 자기변호가 아니라, 하나님의 종으로서 걸어온 길에 대한 확증이었습니다.\n\n이어서 사무엘은 이스라엘의 역사를 되짚으며 하나님의 신실하심을 상기시킵니다. 애굽에서의 구원, 가나안 정착, 그리고 사사들을 통한 구원의 역사가 펼쳐집니다. 그러나 동시에 백성의 반복된 배신도 지적합니다. 하나님을 잊고 바알과 아스다롯을 섬겼던 과거, 그리고 이제는 하나님이 왕이심에도 불구하고 인간 왕을 요구한 현재의 모습까지 낱낱이 드러냅니다.\n\n놀라운 것은 이런 불신앙에도 불구하고 하나님의 약속은 변함이 없다는 사실입니다. 사무엘은 밀 베는 때가 아님에도 우레와 비를 내리시는 기적을 통해 하나님의 주권을 확증합니다. 두려워하는 백성에게 사무엘이 전하는 메시지는 명확합니다. 비록 왕을 구한 것이 잘못이었지만, 이제라도 마음을 다해 여호와를 섬기면 된다는 것입니다. "여호와께서는 그의 크신 이름을 위해서라도 자기 백성을 버리지 아니하실 것"이라는 약속은 하나님의 변함없는 은혜를 보여줍니다.\n\n사무엘은 자신도 기도를 쉬는 것이 죄가 될 것임을 고백하며, 끝까지 백성을 위해 기도하고 가르치겠다고 다짐합니다. 왕정 시대가 시작되었지만, 진정한 왕은 여전히 여호와이심을 잊지 말라는 것이 그의 마지막 당부였습니다.', E'오늘의 핵심\n사무엘은 왕정 시대를 맞이한 이스라엘에게 하나님의 신실하심을 상기시키며, 비록 왕을 세웠지만 여전히 여호와만을 섬겨야 함을 강조합니다.\n\n묵상 질문\n1. 사무엘처럼 청렴하고 정직한 삶의 증거가 내게도 있나요?\n2. 실패와 잘못에도 불구하고 나를 버리지 않으시는 하나님의 은혜를 경험한 적이 있나요?\n3. 내가 쉬지 말고 해야 할 기도의 제목은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-27', E'사마리아와 예루살렘에 임한 심판 (에스겔 23장)', E'에스겔 23장', E'하나님께서는 예루살렘의 죄악을 더욱 생생하게 드러내시기 위해 두 자매의 비유를 사용하십니다. 형 오홀라는 북이스라엘의 수도 사마리아를, 동생 오홀리바는 남유다의 수도 예루살렘을 가리킵니다. 이 두 자매는 애굽에서부터 우상숭배라는 영적 간음을 시작했으며, 약속의 땅에 들어온 후에도 계속해서 주변 강대국들을 의지하며 그들의 우상을 섬겼습니다.\n\n오홀라는 앗수르를 사모하여 그들과 동맹을 맺고 그들의 신을 받아들였지만, 결국 기원전 722년 앗수르에 의해 멸망당했습니다. 하나님께서는 이를 통해 남유다에게 분명한 경고를 주셨습니다. 그러나 오홀리바 예루살렘은 형의 비참한 최후를 목격하고도 회개하기는커녕 오히려 더 심한 우상숭배에 빠져들었습니다. 앗수르뿐 아니라 바벨론의 화려한 문화에 매료되어 그들과 동맹을 맺었다가, 다시 그들을 배신하고 애굽을 의지하는 변덕스러운 모습을 보였습니다.\n\n하나님께서는 이러한 예루살렘의 행태를 "네가 젊었을 때에 행음하여 애굽 사람에게 네 가슴과 유방이 어루만져졌던 것을 아직도 생각하도다"(겔 23:21)라고 묘사하시며, 그들이 하나님과의 언약 관계를 얼마나 가볍게 여겼는지를 드러내십니다. 결국 예루살렘도 그들이 의지했던 바벨론에 의해 멸망당할 것이며, 이는 하나님의 공의로운 심판임을 선포하십니다.\n\n이 비유는 단순히 정치적 동맹의 문제가 아니라, 하나님을 떠나 세상의 힘과 문화를 의지하는 영적 간음의 본질을 보여줍니다. 하나님께서는 자기 백성이 오직 당신만을 신뢰하고 의지하기를 원하시지만, 이스라엘은 끊임없이 눈에 보이는 세상의 화려함에 마음을 빼앗겼습니다. 그럼에도 불구하고 이 엄중한 심판 선언 가운데서도 하나님의 아픔과 안타까움이 배어 있음을 우리는 놓치지 말아야 합니다.', E'오늘의 핵심\n하나님께서는 두 자매의 비유를 통해 이스라엘의 영적 간음, 곧 하나님을 떠나 세상 권력과 우상을 의지한 죄의 심각성을 드러내시고 심판을 선언하십니다.\n\n묵상 질문\n1. 내가 하나님보다 더 의지하고 있는 세상의 힘이나 가치는 무엇인가요?\n2. 다른 사람의 실패를 보면서도 같은 길을 반복하는 이유는 무엇일까요?\n3. 하나님과의 언약 관계를 가볍게 여기는 내 모습은 없는지 점검해 보시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-28', E'사마리아와 예루살렘에 임한 심판 (에스겔 24장)', E'에스겔 24장', E'포위된 지 2년째, 바벨론의 공격이 본격화되던 때에 하나님께서는 에스겔에게 특별한 메시지를 주십니다. 끓는 가마의 비유를 통해 예루살렘의 운명을 보여주신 것입니다. 가마 속의 좋은 고기 덩어리들은 예루살렘의 지도자들을 가리키며, 그들이 뜨거운 불 속에서 삶아지듯 심판받을 것을 예고합니다. 특히 이 가마는 녹이 슬어 있는데, 그 녹은 예루살렘에 쌓인 죄악을 상징합니다. 아무리 끓여도 녹이 벗겨지지 않듯이, 예루살렘의 죄악도 쉽게 씻겨지지 않을 것입니다.\n\n더욱 충격적인 것은 하나님께서 에스겔의 아내를 데려가시면서 슬퍼하지 말라고 명하신 일입니다. 사랑하는 아내의 죽음 앞에서도 애곡하지 못하고 조용히 탄식만 해야 했던 에스겔의 모습은, 곧 닥칠 예루살렘의 비극을 미리 보여주는 표징이었습니다. 백성들이 가장 자랑스러워하던 성전이 무너지고 자녀들이 칼에 쓰러질 때, 그들은 슬퍼할 겨를도 없이 충격에 빠져 서로를 바라보며 탄식만 할 것입니다.\n\n에스겔의 상징적 행동은 하나님께서 주시는 메시지를 더욱 뚜렷하게 전달해 주고 있습니다. 심판의 날이 임했을 때 백성들은 비로소 하나님의 경고가 진실이었음을 깨닫게 될 것입니다. 그러나 그때는 이미 회개하기에 너무 늦은 시점입니다. 하나님께서는 반복된 경고에도 불구하고 돌이키지 않는 백성들에게 마지막 심판을 선언하시면서도, 에스겔을 통해 당신이 참 하나님이심을 알게 하려는 목적을 분명히 하십니다. 심판 속에서도 하나님의 주권과 공의를 드러내시는 것입니다.', E'오늘의 핵심\n하나님께서는 끓는 가마의 비유와 에스겔 아내의 죽음을 통해 예루살렘에 임할 피할 수 없는 심판을 생생하게 보여주셨습니다.\n\n묵상 질문\n1. 반복된 경고에도 회개하지 않는 내 마음의 완고함은 없는지 돌아볼까요?\n2. 하나님의 심판이 임하기 전에 지금 내가 돌이켜야 할 것은 무엇일까요?\n3. 고통스러운 상황 속에서도 하나님의 뜻을 전하는 에스겔처럼, 나는 어떤 순종을 드려야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-29', E'사울의 블레셋 전투 (사무엘상 13장)', E'사무엘상 13장', E'블레셋의 대군이 해변의 모래처럼 몰려오자 이스라엘 백성은 굴과 바위틈에 숨고, 요단 건너편으로 도망치기까지 합니다. 병거 삼만, 마병 육천, 그리고 셀 수 없는 보병의 위세 앞에서 이스라엘은 완전히 위축되었습니다. 사울 곁에 남은 백성마저 하나둘 흩어지고, 겨우 육백 명만이 떨며 그를 따르고 있었습니다.\n\n사무엘이 정한 이레의 기한이 거의 다 되었지만 그는 오지 않았고, 사울의 마음은 조급함으로 가득 찼습니다. 백성은 흩어지고, 적군은 코앞까지 진을 쳤으며, 사무엘은 약속한 시간에 나타나지 않았습니다. 결국 사울은 제사장이 아닌 자신이 직접 번제를 드리기로 결정합니다. 그리고 번제를 마치자마자, 마치 기다렸다는 듯이 사무엘이 도착합니다.\n\n사울의 변명은 그럴듯해 보입니다. "백성은 내게서 흩어지고 당신은 정한 날 안에 오지 아니하고 블레셋 사람은 믹마스에 모였음을 내가 보았으므로"(삼상 13:11). 전쟁을 앞두고 여호와께 은혜를 구하지 못할까 봐 부득이하게 번제를 드렸다는 것입니다. 그러나 사무엘은 이를 ''망령된 행위''라고 단호히 선언합니다.\n\n사울의 근본적인 문제는 상황의 급박함이 아니었습니다. 그의 마음에 하나님을 온전히 신뢰하고 기다리는 자리가 없었다는 것이 문제였습니다. 사울에게 번제는 하나님 앞에 자신을 내려놓는 예배가 아니라, 백성의 민심을 수습하고 전쟁의 승리를 보장받기 위한 수단에 불과했습니다. 그는 보이는 상황에 압도되어 보이지 않는 하나님의 때를 기다리지 못했습니다.\n\n이 사건으로 인해 사울은 왕위를 잃게 됩니다. 하나님께서는 "그의 마음에 맞는 사람"을 이미 준비하고 계셨습니다. 작은 불순종처럼 보이지만, 이는 사울의 마음 중심이 하나님이 아닌 자신과 상황에 있음을 드러낸 결정적인 사건이었습니다. 하나님께서는 능력이 아닌 마음을 보시며, 성과가 아닌 순종을 기뻐하십니다. 오늘도 우리는 ''부득이하다''는 핑계로 하나님의 방법 대신 내 방식을 선택하려는 유혹을 받습니다. 그러나 진정한 믿음은 보이는 현실이 아닌 보이지 않는 하나님의 약속을 붙잡고 끝까지 기다리는 것입니다.', E'오늘의 핵심\n사울은 급박한 상황을 핑계로 하나님의 명령을 어기고 스스로 번제를 드렸으며, 이는 그의 마음이 하나님께 온전히 향하지 않았음을 보여주는 결정적인 사건이 되었습니다.\n\n묵상 질문\n1. 내가 ''부득이하다''며 하나님의 뜻보다 내 판단을 앞세웠던 때는 언제인가요?\n2. 상황이 급박할 때 하나님을 끝까지 기다린다는 것은 무엇을 의미할까요?\n3. 오늘 내 삶에서 하나님의 때를 기다려야 할 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-30', E'사울의 블레셋 전투 (사무엘상 14장)', E'사무엘상 14장', E'하루는 요나단이 무기 든 소년과 단둘이 블레셋 진영으로 향합니다. 사울이 육백 명의 병사와 함께 석류나무 아래 머물러 있는 동안, 그의 아들은 믿음의 모험을 시작한 것입니다. 험한 바위 사이를 지나며 요나단이 한 고백은 놀랍습니다. "여호와의 구원은 사람이 많고 적음에 달리지 아니하였느니라." 이는 단순한 용기가 아니라 하나님의 능력을 온전히 신뢰하는 믿음의 고백이었습니다.\n\n요나단은 하나님께서 주실 표징을 구하며 나아갑니다. 블레셋 사람들이 "우리에게로 올라오라"고 말하면 그것을 하나님께서 그들을 넘기신 증거로 받아들이겠다는 것이었습니다. 그리고 정확히 그 일이 일어납니다. 요나단과 그의 무기 든 자가 처음 쳐죽인 자가 이십 명 가량이었고, 이어서 하나님께서 블레셋 진영에 큰 떨림을 일으키셨습니다. 땅까지 진동하는 이 혼란은 하나님께서 직접 개입하신 초자연적인 역사였습니다.\n\n그런데 승리의 날에 사울은 또다시 잘못된 결정을 내립니다. "저녁까지 아무 음식물이든지 먹는 사람은 저주를 받을지어다"라는 성급한 맹세를 한 것입니다. 이로 인해 백성들은 극도로 피곤해졌고, 결국 피째로 고기를 먹는 죄를 범하게 됩니다. 요나단이 꿀을 먹고 눈이 밝아진 것과 대조적으로, 사울의 경솔한 맹세는 오히려 백성을 죄에 빠뜨리고 승리를 제한하는 결과를 낳았습니다.\n\n같은 전쟁터에서 아버지와 아들은 전혀 다른 모습을 보여줍니다. 요나단은 하나님을 신뢰하며 담대히 나아갔고, 사울은 인간적인 열심으로 잘못된 명령을 내렸습니다. 요나단의 믿음은 하나님의 큰 역사를 이끌어냈지만, 사울의 맹세는 백성을 곤경에 빠뜨렸습니다. 하나님께서는 한 사람의 온전한 믿음을 통해서도 능히 구원을 이루실 수 있음을 이 본문은 생생히 보여주고 있습니다.', E'오늘의 핵심\n요나단의 믿음 있는 행동은 하나님의 놀라운 승리로 이어졌지만, 사울의 성급한 맹세는 오히려 백성을 죄에 빠뜨리는 걸림돌이 되었습니다.\n\n묵상 질문\n1. 요나단처럼 "여호와의 구원은 사람의 많고 적음에 달리지 않았다"고 고백할 수 있는 믿음이 내게 있나요?\n2. 나의 열심이 오히려 하나님의 일을 방해하거나 다른 사람에게 무거운 짐이 된 적은 없었나요?\n3. 오늘 내가 직면한 상황에서 하나님의 능력을 온전히 신뢰하며 나아갈 일은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-07-31', E'사울의 불순종과 다윗의 기름 부음 (사무엘상 15장)', E'사무엘상 15장', E'사울이 왕이 된 지 20여 년, 이스라엘은 주변 민족들과의 전쟁에서 승리를 거듭하며 강성해졌습니다. 이때 하나님께서는 사울에게 특별한 사명을 주십니다. 아말렉을 완전히 진멸하라는 것이었습니다. 아말렉은 이스라엘이 출애굽할 때 대열에서 뒤처진 약자들을 공격했던 민족입니다. 수백 년이 지났지만 그들은 여전히 약한 자들을 괴롭히는 삶을 이어가고 있었고, 공의의 하나님께서는 그들의 악행에 대한 심판을 명하셨습니다.\n\n사울은 20만의 군대를 이끌고 아말렉을 공격해 승리를 거둡니다. 그러나 하나님의 명령을 온전히 수행하지는 않았습니다. 왕 아각을 사로잡고, 좋은 가축들을 남겨두었던 것입니다. 돌아온 사울은 사무엘에게 "내가 여호와의 명령을 행하였나이다"라고 보고하지만, 사무엘의 귀에는 양과 소의 울음소리가 들려왔습니다. \n\n사울의 변명은 계속됩니다. 백성들이 하나님께 제사하려고 좋은 것들을 남겼다고 말합니다. 그러나 사무엘은 그 유명한 말씀을 선포합니다. "순종이 제사보다 낫고 듣는 것이 숫양의 기름보다 나으니"(삼상 15:22). 하나님께서 원하시는 것은 화려한 제사가 아니라 그분의 말씀에 대한 온전한 순종이었습니다.\n\n사울은 자신의 잘못을 인정하면서도 그 이유를 백성에 대한 두려움 때문이라고 고백합니다. 하나님보다 사람을 더 두려워했던 것입니다. 더욱이 그는 이스라엘을 "내 백성"이라고 부르며, 하나님의 백성을 자신의 소유로 여기는 교만함까지 드러냅니다. 결국 사무엘은 하나님께서 사울을 왕위에서 폐하셨다는 엄중한 선고를 전합니다. 거역은 점치는 죄와 같고, 완고함은 우상숭배와 같다는 말씀과 함께 말입니다.\n\n라마로 돌아간 사무엘은 죽는 날까지 사울을 다시 보지 않았습니다. 한 시대를 이끌어야 할 지도자가 하나님의 말씀에 불순종함으로써 버림받은 것에 대한 깊은 슬픔이 그의 마음을 무겁게 했습니다.', E'오늘의 핵심\n하나님께서는 형식적인 종교 행위보다 말씀에 대한 온전한 순종을 원하시며, 사람을 두려워하여 하나님의 명령을 어긴 사울을 왕위에서 폐하셨습니다.\n\n묵상 질문\n1. 내가 하나님께 드리는 예배와 헌신 속에 진정한 순종이 있나요, 아니면 형식적인 종교 행위에 머물러 있나요?\n2. 하나님의 뜻을 알면서도 사람들의 시선이나 평가 때문에 순종하지 못한 경험이 있다면 무엇인가요?\n3. 오늘 하나님께서 내게 요구하시는 ''완전한 순종''의 영역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-02', E'사울의 불순종과 다윗의 기름 부음 (사무엘상 16장)', E'사무엘상 16장', E'사울이 하나님의 말씀에 불순종한 결과는 참으로 엄중했습니다. 하나님께서는 사무엘을 통해 사울을 버리셨다는 선언을 하셨고, 이제 새로운 왕을 준비하십니다. 사무엘이 사울을 위해 슬퍼하고 있을 때, 하나님께서는 "언제까지 슬퍼하겠느냐"고 물으시며 베들레헴으로 가서 이새의 아들 중 한 명에게 기름을 부으라고 명하십니다. 사무엘이 사울의 보복을 두려워하자, 하나님께서는 제사를 핑계로 가라는 지혜로운 방법을 알려주십니다.\n\n베들레헴에 도착한 사무엘 앞에 이새의 아들들이 차례로 나타납니다. 첫째 엘리압을 본 사무엘은 그의 훌륭한 외모에 감탄하며 이 사람이 하나님의 기름부음 받을 자라고 확신했습니다. 그러나 하나님께서는 "그의 용모와 키를 보지 말라 내가 이미 그를 버렸노라 내가 보는 것은 사람과 같지 아니하니 사람은 외모를 보거니와 나 여호와는 중심을 보느니라"(삼상 16:7)고 말씀하십니다. 이 말씀은 하나님의 선택 기준이 인간의 기준과 얼마나 다른지를 보여줍니다.\n\n일곱 아들이 모두 지나갔지만 아무도 택함받지 못했습니다. 사무엘이 다른 아들이 있는지 묻자, 이새는 막내가 양을 치고 있다고 대답합니다. 양을 치던 막내 다윗이 불려왔을 때, 하나님께서는 바로 그가 택한 자임을 알려주셨고, 사무엘은 그에게 기름을 부었습니다. 그 순간부터 다윗은 여호와의 영에 크게 감동되었습니다.\n\n반면 사울에게서는 여호와의 영이 떠나고 악령이 그를 괴롭히기 시작했습니다. 신하들의 제안으로 수금을 잘 타는 자를 찾던 중, 바로 그 다윗이 사울의 궁으로 부름받게 됩니다. 다윗이 수금을 탈 때마다 사울을 괴롭히던 악령이 떠나갔습니다. 이렇게 하나님께서는 버림받은 왕과 새로 택함받은 왕을 한 자리에 모으시며, 새로운 시대를 준비하십니다. 하나님의 섭리는 참으로 오묘하여, 다윗은 자신이 대체할 왕을 섬기는 것으로 왕의 길을 시작하게 됩니다.', E'오늘의 핵심\n하나님께서는 외모가 아닌 중심을 보시며 다윗을 택하셨고, 여호와의 영이 사울에게서 떠나 다윗에게 임하면서 이스라엘의 새로운 시대가 열립니다.\n\n묵상 질문\n1. 하나님께서 사람의 중심을 보신다는 말씀이 내게는 위로가 되나요, 아니면 부담이 되나요?\n2. 내가 사람을 평가할 때 외모나 조건을 먼저 보고 있지는 않은가요?\n3. 다윗처럼 낮은 자리에서도 충실히 섬길 준비가 되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-03', E'애굽에 대한 심판 (에스겔 29장)', E'에스겔 29장', E'포로 생활 열 번째 해가 되었을 때, 하나님께서는 에스겔을 통해 애굽에 대한 심판을 선포하십니다. 당시 애굽은 고대 근동의 강대국으로서 많은 나라들이 의지하려 했던 나라였습니다. 남유다 역시 바벨론의 위협 앞에서 하나님보다는 애굽의 군사력을 의지하려 했습니다. 그러나 하나님께서는 애굽의 교만한 바로를 "자기의 강들 가운데에 누운 큰 악어"로 묘사하시며 그들의 멸망을 예고하십니다.\n\n애굽 왕 바로의 교만은 극에 달해 있었습니다. 그는 "나의 이 강은 내 것이라 내가 나를 위하여 만들었다"고 선언합니다. 나일강의 풍요로움이 애굽 문명의 기초가 되었지만, 바로는 그 모든 것이 자신의 능력으로 이루어진 것처럼 여겼습니다. 창조주 하나님을 인정하지 않고 자신을 신격화하는 바로의 모습은 하나님의 심판을 자초하는 것이었습니다.\n\n하나님께서는 갈고리로 악어를 낚듯이 애굽을 끌어내어 들에 던지실 것이라고 선언하십니다. 더욱이 애굽은 이스라엘에게 "갈대 지팡이"와 같았다고 말씀하십니다. 겉으로는 든든해 보이지만 실제로 기댔을 때는 부러져서 오히려 상처만 입히는 존재였던 것입니다. 이것은 하나님을 신뢰하지 않고 세상의 힘을 의지했던 이스라엘 백성들에게 주시는 뼈아픈 교훈이었습니다.\n\n그러나 하나님의 심판 가운데서도 회복의 소망이 보입니다. 애굽이 40년간 황폐하게 된 후 다시 모여질 것이며, 비록 미약한 나라가 되지만 완전히 멸망하지는 않을 것이라는 약속입니다. 이는 하나님의 심판이 단순한 파괴가 아니라 교만을 꺾고 하나님을 인정하도록 하시는 징계임을 보여줍니다. 느부갓네살을 통한 애굽 정벌도 결국 "내가 여호와인 줄을 그들이 알리라"는 하나님의 궁극적인 목적을 이루기 위한 것이었습니다.', E'오늘의 핵심\n하나님께서는 교만한 애굽을 심판하심으로써 이스라엘과 열방이 참된 의지처는 오직 여호와 하나님이심을 깨닫게 하십니다.\n\n묵상 질문\n1. 내가 이룬 성취를 하나님의 은혜가 아닌 내 능력으로 여긴 적은 없나요?\n2. 하나님보다 세상의 힘과 방법을 더 의지하고 있는 영역은 무엇인가요?\n3. 하나님의 징계 속에서도 회복의 소망을 발견할 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-04', E'애굽에 대한 심판 (에스겔 30장)', E'에스겔 30장', E'하나님께서는 에스겔을 통해 애굽에 임할 재앙의 날을 선포하십니다. "구름의 날"이라 불리는 그날은 단지 애굽만이 아니라 여러 나라들에게 심판의 때가 될 것입니다. 애굽과 동맹을 맺은 구스, 붓, 룻을 비롯한 주변 나라들도 함께 멸망할 것이라는 경고는 세상의 힘을 의지하는 것이 얼마나 허망한지를 보여줍니다.\n\n특히 하나님께서는 애굽의 우상들과 신상들을 부수시고, 다시는 애굽 땅에서 왕이 나지 못하게 하시겠다고 선언하십니다. 나일강의 풍요를 자랑하던 애굽의 주요 도시들 - 놉, 소안, 신, 아웬, 비베셋, 드합느헤스 - 은 모두 파괴되고 그 주민들은 포로가 될 것입니다. 애굽이 자랑하던 "교만한 권세"는 완전히 꺾일 것입니다.\n\n바로 왕의 팔을 꺾으시는 하나님의 심판은 매우 상징적입니다. 이미 한 팔이 꺾였는데도 제대로 치료하지 못한 바로는, 이제 성한 팔마저 꺾여 더 이상 칼을 잡을 수 없게 됩니다. 반면 바벨론 왕의 팔은 견고해지고 하나님의 칼을 받아 애굽을 치게 됩니다. 이는 하나님께서 역사의 주관자로서 열방을 다스리시며, 교만한 자를 낮추시고 당신의 도구로 사용하실 자를 높이신다는 것을 보여줍니다.\n\n하나님께서는 이 모든 심판을 통해 "내가 여호와인 줄을 그들이 알리라"고 반복하여 말씀하십니다. 애굽의 멸망은 단순한 정치적 사건이 아니라, 온 세상의 참된 주권자가 누구인지를 만방에 알리시는 하나님의 계시적 행동입니다. 세상의 힘과 우상을 의지하던 애굽이 무너질 때, 비로소 사람들은 여호와 하나님만이 참 하나님이심을 깨닫게 될 것입니다.', E'오늘의 핵심\n하나님께서는 교만한 애굽을 심판하시며 바벨론을 들어 사용하심으로써, 당신이 역사의 주관자이시며 온 세상의 참된 통치자이심을 만방에 나타내십니다.\n\n묵상 질문\n1. 애굽의 팔은 꺾이고 바벨론의 팔은 견고해지는 모습을 통해 하나님은 무엇을 가르치시나요?\n2. 내가 하나님보다 더 의지하고 있는 세상의 힘이나 우상은 무엇인가요?\n3. "내가 여호와인 줄 알리라"는 말씀이 오늘 나의 삶에 어떤 의미가 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-05', E'애굽에 대한 심판 (에스겔 31장)', E'에스겔 31장', E'한때 영광스러웠던 앗수르의 몰락을 통해 애굽의 운명을 예언하는 하나님의 말씀이 에스겔에게 임합니다. 하나님께서는 애굽의 바로에게 묻습니다. "네 큰 위엄을 누구에게 비하랴"(겔 31:2). 이어서 앗수르를 레바논의 백향목에 비유하며 그들의 과거 영광을 상세히 묘사하십니다. 풍부한 물로 자라나 하늘 높이 솟은 거대한 나무, 모든 새들이 깃들이고 모든 짐승이 그늘 아래 쉬며 열방이 그 아래 거하던 웅장한 나무의 모습은 한때 세계를 호령하던 앗수르 제국의 위용을 생생하게 보여줍니다.\n\n그러나 이 아름다운 나무는 교만으로 인해 무너집니다. 하나님의 동산 에덴의 모든 나무가 시기할 만큼 아름다웠던 그 나무는 자신의 높이와 영광을 스스로의 것으로 여기며 교만해졌습니다. 그 결과 하나님께서는 이방 민족의 손에 그들을 넘기셨고, 한때 세상을 지배하던 거대한 나무는 찍혀 쓰러졌습니다. 산과 골짜기에 가지가 흩어지고, 그 그늘 아래 있던 모든 이들이 떠나갔으며, 결국 스올로 내려가게 되었습니다.\n\n이 비유는 단순히 과거 앗수르의 이야기가 아닙니다. 하나님께서는 애굽의 바로에게 앗수르의 운명이 곧 애굽의 운명이 될 것임을 경고하고 계십니다. 나일 강의 풍요로움을 자랑하며 "나의 이 강은 내 것이라"고 외치던 애굽도 앗수르처럼 교만으로 인해 심판받을 것입니다. 하나님께서 주신 은혜와 번영을 자신의 공로로 돌리는 교만은 필연적으로 몰락을 가져옵니다. 물 가에 있는 모든 나무가 스스로 높아지지 못하게 하시는 이유는 모든 권세와 영광이 오직 하나님께로부터 온다는 진리를 깨닫게 하시기 위함입니다.', E'오늘의 핵심\n하나님께서는 앗수르의 흥망성쇠를 통해 애굽에게 경고하시며, 교만은 반드시 몰락으로 이어진다는 역사의 교훈을 가르치십니다.\n\n묵상 질문\n1. 내가 이룬 성취와 받은 축복을 누구의 것으로 여기고 있나요?\n2. 앗수르처럼 하나님의 은혜를 자신의 공로로 착각한 적은 없나요?\n3. 겸손히 하나님의 주권을 인정하며 살아가려면 어떤 노력이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-06', E'애굽에 대한 심판 (에스겔 32장)', E'에스겔 32장', E'에스겔 선지자는 애굽의 마지막 운명을 장송곡의 형태로 전달합니다. 이전까지 사자로 여겨졌던 애굽의 바로는 이제 "바다 가운데의 큰 악어"(겔 32:2)로 묘사되며, 그가 강물을 휘저어 더럽혔던 것처럼 하나님의 그물에 걸려 뭍으로 끌려 나올 것임을 보여줍니다. 애굽의 멸망은 단순한 한 나라의 패망을 넘어서 우주적 심판의 성격을 띱니다. 해와 달과 별들이 어두워지고 온 땅이 흑암으로 뒤덮이는 묘사는 창조 질서가 뒤집어지는 듯한 종말론적 심판을 연상시킵니다.\n\n본문의 후반부는 스올, 곧 음부에 내려간 열방들의 처참한 운명을 보여줍니다. 한때 세상을 두렵게 했던 앗수르, 엘람, 메섹과 두발, 에돔, 그리고 시돈까지 모두가 죽음의 구덩이에서 수치를 당하고 있습니다. 이들은 생전에 강대한 힘으로 다른 나라들을 위협했지만, 이제는 할례받지 못한 자들과 함께 누워 있을 뿐입니다. 특히 주목할 점은 하나님께서 바로에게 이러한 광경을 보여주시며 "위로를 받을 것"이라고 말씀하신다는 것입니다. 이는 애굽도 결국 다른 교만한 나라들과 같은 운명을 맞이할 것임을 암시합니다.\n\n이 엄중한 심판의 메시지는 단순히 고대 애굽만을 향한 것이 아닙니다. 하나님의 주권을 인정하지 않고 자신의 힘과 영광을 자랑하는 모든 세력에 대한 경고입니다. 나일강을 "내 것이라"고 주장했던 바로의 교만은 오늘날에도 하나님 없이 살아가려는 인간의 모습 속에서 반복됩니다. 그러나 역사의 주관자이신 하나님께서는 교만한 자를 낮추시고, 결국 모든 열방이 "내가 여호와인 줄" 알게 하실 것입니다. 이것이 심판 가운데서도 빛나는 하나님의 궁극적인 목적입니다.', E'오늘의 핵심\n하나님께서는 애굽과 열방의 심판을 통해 역사의 진정한 주관자가 누구인지를 분명히 드러내시며, 교만한 자들의 종말이 어떠한지를 엄중히 경고하십니다.\n\n묵상 질문\n1. 한때 강대했던 나라들이 모두 스올에 누워있는 모습을 통해 하나님은 무엇을 가르치시나요?\n2. 내 삶에서 "이것은 내 것이라"고 주장하며 하나님의 주권을 인정하지 않는 영역은 없나요?\n3. 심판의 메시지 속에서도 하나님을 알게 하시려는 그분의 마음을 어떻게 이해할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-07', E'그리스도 안에서 하나 됨 (에베소서 4장)', E'에베소서 4장', E'바울은 로마 감옥에서 에베소 교회에 편지를 쓰면서 간절한 권면으로 시작합니다. "너희가 부르심을 받은 일에 합당하게 행하여"라는 말씀은 앞선 3장까지 설명한 하나님의 구원 계획에 대한 응답으로서의 삶을 요구하는 것입니다. 창세 전부터 우리를 택하시고 자녀 삼으신 그 놀라운 은혜에 걸맞은 삶의 모습이 무엇인지를 구체적으로 제시합니다.\n\n그 합당한 삶은 먼저 겸손과 온유, 오래 참음과 사랑으로 서로를 용납하는 것에서 시작됩니다. 특히 바울은 "성령이 하나 되게 하신 것을 힘써 지키라"고 강조합니다. 교회의 하나 됨은 우리가 만들어내는 것이 아니라 성령께서 이미 이루어 놓으신 선물입니다. 한 몸, 한 성령, 한 소망, 한 주, 한 믿음, 한 세례, 한 하나님—이 일곱 가지 ''하나''는 모든 다양성을 품어내는 통일성의 근거가 됩니다.\n\n그리스도께서는 승천하시면서 교회에 다양한 은사를 주셨습니다. 사도, 선지자, 복음 전하는 자, 목사와 교사—이들은 모두 성도를 온전하게 하여 봉사의 일을 하게 하고 그리스도의 몸을 세우기 위한 것입니다. 교회는 이러한 은사들이 조화롭게 연결되어 사랑 안에서 자라가는 유기체입니다.\n\n바울은 이어서 매우 실제적인 권면을 합니다. 옛 사람을 벗어버리고 새 사람을 입으라는 것입니다. 이것은 단순한 도덕적 개선이 아니라 존재의 변화를 말합니다. 거짓 대신 참된 것을 말하고, 분을 품어 마귀에게 틈을 주지 말며, 더러운 말 대신 덕을 세우는 말을 하라고 합니다. 특히 "서로 용서하기를 하나님이 그리스도 안에서 너희를 용서하심과 같이 하라"는 말씀은 그리스도인의 관계 윤리의 핵심을 보여줍니다.\n\n이 모든 권면의 기초는 하나님께서 먼저 우리에게 베푸신 은혜입니다. 우리가 겸손할 수 있는 것은 하나님께서 먼저 자신을 낮추셨기 때문이며, 우리가 용서할 수 있는 것은 먼저 용서받았기 때문입니다. 부르심에 합당한 삶은 은혜를 받은 자의 감사의 응답입니다.', E'오늘의 핵심\n바울은 하나님의 부르심에 합당하게 살되, 겸손과 온유로 서로 용납하며 성령이 주신 하나 됨을 지키고, 옛 사람을 벗고 새 사람을 입어 그리스도의 몸을 세워가라고 권면합니다.\n\n묵상 질문\n1. 내가 받은 하나님의 부르심에 합당하게 살기 위해 오늘 실천할 수 있는 겸손과 온유는 무엇인가요?\n2. 우리 공동체 안에서 성령이 주신 하나 됨을 깨뜨리는 요소는 무엇이며, 어떻게 지켜갈 수 있을까요?\n3. 하나님이 그리스도 안에서 나를 용서하신 것처럼, 오늘 내가 용서해야 할 사람은 누구입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-09', E'그리스도 안에서 하나 됨 (에베소서 5장)', E'에베소서 5장', E'바울은 에베소 교회 성도들에게 "사랑을 받는 자녀 같이 하나님을 본받는 자가 되라"고 권면합니다. 하나님의 자녀로서 마땅히 행해야 할 삶의 모습을 구체적으로 제시하는 것입니다. 그 핵심은 그리스도께서 우리를 위해 자신을 향기로운 제물로 드리신 것처럼, 우리도 사랑 가운데서 행하라는 것입니다.\n\n사랑의 삶은 단순히 좋은 말과 행동만을 의미하지 않습니다. 바울은 성도의 삶에서 완전히 제거해야 할 것들을 분명히 지적합니다. 음행과 더러운 것과 탐욕은 그 이름조차 부르지 말아야 하며, 누추함과 어리석은 말과 희롱의 말을 버리고 감사하는 말로 대체해야 합니다. 이러한 변화는 우리가 "전에는 어둠이었으나 이제는 주 안에서 빛"이 되었기 때문입니다.\n\n빛의 자녀로 살아간다는 것은 모든 착함과 의로움과 진실함의 열매를 맺는 것입니다. 바울은 열매 없는 어둠의 일에 참여하지 말고 도리어 책망하라고 권면합니다. 그리고 잠자는 자에게 깨어나라는 강력한 호소를 통해, 그리스도의 빛 비추심을 받은 자답게 살 것을 촉구합니다.\n\n특별히 바울은 지혜로운 삶의 실천을 강조합니다. 세월을 아끼고, 주의 뜻을 이해하며, 술 취함 대신 성령 충만함을 받으라는 것입니다. 성령 충만한 삶의 증거는 시와 찬송과 신령한 노래로 서로 화답하며, 범사에 감사하는 것으로 나타납니다.\n\n에베소서 5장의 후반부는 그리스도와 교회의 관계를 통해 부부관계의 신비를 설명합니다. 아내는 교회가 그리스도께 순종하듯 남편에게 순종하고, 남편은 그리스도께서 교회를 위해 자신을 주신 것처럼 아내를 사랑해야 합니다. 이는 단순한 역할 분담이 아니라, 그리스도와 교회의 연합이라는 큰 비밀을 드러내는 거룩한 관계입니다. 바울은 창세기의 "둘이 한 육체가 될지니"라는 말씀을 인용하며, 이것이 그리스도와 교회의 신비로운 연합을 가리킨다고 해석합니다.', E'오늘의 핵심\n하나님의 사랑받는 자녀로서 우리는 어둠의 일을 버리고 빛의 자녀답게 살아가며, 성령 충만함 가운데 감사와 찬송이 넘치는 삶을 살아야 합니다.\n\n묵상 질문\n1. 내가 아직도 버리지 못한 어둠의 습관이나 말은 무엇인가요?\n2. 성령 충만함이 나의 일상에서 어떻게 나타나고 있나요?\n3. 그리스도께서 교회를 사랑하신 것처럼 내가 희생적 사랑을 실천할 관계는 어디인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-10', E'그리스도 안에서 하나 됨 (에베소서 6장)', E'에베소서 6장', E'바울은 에베소서의 마지막 장에서 그리스도인의 일상적 관계와 영적 전투라는 두 가지 중요한 주제를 다룹니다. 먼저 가정과 사회 속에서의 관계들을 다루는데, 이는 앞서 말한 ''부르심에 합당한 삶''의 구체적인 모습입니다.\n\n자녀와 부모의 관계에서 바울은 "주 안에서" 순종하라고 권면합니다. 이는 단순한 복종이 아니라 주님을 인정하는 마음에서 나오는 순종입니다. 부모 공경은 약속이 있는 첫 계명으로, 하나님께서 직접 복을 약속하신 명령입니다. 동시에 부모들에게는 자녀를 노엽게 하지 말고 "주의 교훈과 훈계로" 양육하라고 합니다. 양육의 기준이 부모의 감정이나 권위가 아니라 주님의 말씀이어야 한다는 뜻입니다.\n\n종과 상전의 관계에서도 바울은 놀라운 원칙을 제시합니다. 종들은 "그리스도께 하듯" 상전을 섬기고, 상전들은 위협을 그치라고 합니다. 왜냐하면 하늘에 계신 주님은 사람을 외모로 취하지 않으시기 때문입니다. 이는 당시의 사회 구조를 인정하면서도 그 안에서 그리스도인다운 관계를 맺으라는 가르침입니다.\n\n바울은 이어서 영적 전투의 실체를 밝힙니다. "우리의 씨름은 혈과 육을 상대하는 것이 아니요"라는 선언은 우리가 싸워야 할 진짜 적이 누구인지 보여줍니다. 통치자들과 권세들, 어둠의 세상 주관자들과 악의 영들이 우리의 대적입니다. 그래서 하나님의 전신갑주가 필요합니다. 진리의 허리띠, 의의 호심경, 평안의 복음의 신, 믿음의 방패, 구원의 투구, 성령의 검—이 여섯 가지 무기는 방어와 공격을 모두 가능하게 합니다.\n\n특별히 주목할 것은 이 모든 영적 무장 후에 "모든 기도와 간구"를 하라는 명령입니다. 영적 전투는 궁극적으로 기도의 자리에서 승부가 결정됩니다. 바울 자신도 쇠사슬에 매인 상황에서 복음을 담대히 전할 수 있도록 기도를 요청합니다. 이것이 하나님의 능력 안에서 강건해지는 비결입니다.', E'오늘의 핵심\n바울은 일상의 관계 속에서 "주 안에서" 살아가는 법과 영적 전투를 위해 하나님의 전신갑주로 무장하고 기도로 싸우는 그리스도인의 삶을 가르칩니다.\n\n묵상 질문\n1. 내가 맺고 있는 관계들(가정, 직장)에서 "그리스도께 하듯" 행하고 있나요?\n2. 내 삶의 어려움을 사람과의 싸움이 아닌 영적 전투로 인식하고 있습니까?\n3. 하나님의 전신갑주 중에서 오늘 특별히 필요한 것은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-11', E'다윗의 골리앗 전투 승리와 요나단과의 우정 (사무엘상 17장)', E'사무엘상 17장', E'엘라 골짜기에서 이스라엘과 블레셋의 군대가 40일째 대치하고 있었습니다. 블레셋의 장수 골리앗은 여섯 규빗 한 뼘(약 3m)의 거대한 키에 놋 투구와 5천 세겔(약 57kg)의 갑옷으로 무장한 채 매일 이스라엘을 조롱하며 도전했습니다. "너희는 한 사람을 택하여 내게로 내려보내라"(삼상 17:8)는 골리앗의 외침에 사울과 온 이스라엘은 크게 두려워했습니다.\n\n바로 이때 아버지 이새의 심부름으로 형들에게 음식을 전하러 온 목동 다윗이 이 광경을 목격합니다. 다윗의 눈에 비친 것은 단순히 거대한 적장이 아니라 "살아 계시는 하나님의 군대를 모욕하는" 할례받지 않은 블레셋 사람이었습니다. 큰형 엘리압은 다윗의 담대함을 교만으로 오해하며 꾸짖었지만, 다윗은 흔들리지 않았습니다.\n\n사울 앞에 선 다윗은 자신의 목동 경험을 들어 확신을 전합니다. 양을 지키며 사자와 곰을 물리쳤던 것처럼, 여호와께서 이번에도 자신을 건져주실 것이라는 믿음이었습니다. 왕의 군복과 갑옷 대신 평소 익숙한 물매와 시냇가의 매끄러운 돌 다섯 개를 택한 다윗의 모습은 하나님께서 일하시는 방식을 보여줍니다. 세상의 힘과 무기가 아닌, 여호와를 향한 신뢰가 진정한 무기임을 다윗은 알고 있었던 것입니다.\n\n베들레헴의 무명 목동이었던 다윗을 통해 하나님께서는 당신의 이름과 백성을 지키시는 분이심을 드러내십니다. 두려움에 사로잡힌 이스라엘 군대와 대조되는 다윗의 담대함은 하나님의 살아계심을 믿는 믿음에서 나온 것이었습니다.', E'오늘의 핵심\n하나님께서는 거대한 골리앗 앞에서 두려워하는 이스라엘을 위해 믿음의 목동 다윗을 준비시키셨습니다. 다윗의 담대함은 살아계신 하나님을 향한 신뢰에서 나왔습니다.\n\n묵상 질문\n1. 내 삶의 골리앗은 무엇이며, 그것이 나를 두렵게 만드는 이유는 무엇인가요?\n2. 다윗처럼 일상의 작은 경험 속에서 하나님의 신실하심을 발견한 적이 있나요?\n3. 세상의 방법이 아닌 하나님의 방법으로 문제를 해결하려면 어떤 믿음이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-12', E'다윗의 골리앗 전투 승리와 요나단과의 우정 (사무엘상 18장)', E'사무엘상 18장', E'골리앗과의 싸움에서 승리한 다윗이 사울 앞에 서게 되었을 때, 놀라운 일이 일어납니다. 왕세자 요나단의 마음이 다윗의 마음과 하나가 되어 그를 자기 생명 같이 사랑하게 된 것입니다. 요나단은 다윗과 언약을 맺고 자신의 겉옷과 군복, 그리고 칼과 활과 띠까지 벗어 주었습니다. 왕위 계승자가 자신의 왕권을 상징하는 물품들을 다윗에게 넘겨준 이 행위는 단순한 우정을 넘어서는 깊은 의미를 담고 있습니다.\n\n사울은 다윗을 자기 곁에 머물게 하고 군대의 장으로 삼았습니다. 다윗은 사울이 보내는 곳마다 가서 지혜롭게 행동했고, 온 백성과 사울의 신하들도 그를 합당하게 여겼습니다. 그런데 블레셋과의 전쟁에서 돌아올 때 여인들이 "사울이 죽인 자는 천천이요 다윗은 만만이로다"라고 노래하자, 사울의 마음에 시기와 두려움이 일어나기 시작합니다.\n\n그날 이후 사울은 다윗을 주목하며 경계했고, 악령이 그를 사로잡을 때마다 다윗을 해치려 했습니다. 사울은 다윗을 제거하려는 계략을 꾸며 딸들을 미끼로 사용하기까지 했습니다. 처음에는 맏딸 메랍을 주겠다고 했다가 다른 사람에게 주었고, 다윗을 사랑하는 둘째 딸 미갈을 주면서도 블레셋 사람들의 포피 백 개를 요구하여 그가 전쟁에서 죽기를 바랐습니다.\n\n그러나 하나님께서 다윗과 함께하셨기에 그는 모든 위험을 극복하고 오히려 이백 명의 블레셋 사람을 죽여 왕의 요구를 두 배로 채웠습니다. 사울은 여호와께서 다윗과 함께 계심을 알고 더욱 두려워했고, 평생 다윗의 대적이 되어버렸습니다. 한 사람의 시기심이 어떻게 영혼을 파괴하고 관계를 망가뜨리는지를 보여주는 안타까운 장면입니다.', E'오늘의 핵심\n하나님이 함께하시는 다윗을 요나단은 생명처럼 사랑했지만, 사울은 시기와 두려움으로 대적했습니다. 같은 사람을 보면서도 전혀 다른 반응을 보이는 두 사람의 모습이 우리에게 많은 것을 생각하게 합니다.\n\n묵상 질문\n1. 하나님이 쓰시는 사람을 볼 때 나는 요나단처럼 기뻐하나요, 아니면 사울처럼 시기하나요?\n2. 시기심이 내 마음을 사로잡을 때 어떻게 그것을 극복할 수 있을까요?\n3. 하나님이 함께하시는 삶의 증거가 내게도 나타나고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-13', E'다윗의 골리앗 전투 승리와 요나단과의 우정 (사무엘상 19장)', E'사무엘상 19장', E'사울의 질투가 살의로 변하면서 다윗의 생명이 위태로워집니다. 하나님께서 다윗과 함께하시는 것을 누구보다 잘 알던 사울이었지만, 왕권에 대한 집착이 그의 판단력을 흐리게 만들었습니다. 이때 요나단의 우정이 빛을 발합니다. 아버지의 명령보다 하나님의 뜻과 의로움을 더 중요하게 여긴 요나단은 다윗의 생명을 구하기 위해 적극적으로 나섭니다. \n\n요나단의 중재로 잠시 화해가 이루어지는 듯했지만, 다윗이 또다시 블레셋과의 전쟁에서 큰 승리를 거두자 사울의 시기심은 다시 타오릅니다. 악령에 사로잡힌 사울이 단창을 던져 다윗을 죽이려 하는 장면은 한때 다윗의 수금 소리로 평안을 얻었던 왕의 변화된 모습을 극명하게 보여줍니다. \n\n위기의 순간, 하나님께서는 미갈을 통해 다윗을 보호하십니다. 사울의 딸이면서 다윗의 아내인 미갈이 남편을 창문으로 내려보내고 꾀를 써서 추격을 늦춘 것은 하나님의 섭리였습니다. 다윗이 사무엘에게로 피신한 후에 일어난 일은 더욱 놀랍습니다. 다윗을 잡으러 온 사울의 전령들이 오히려 하나님의 영에 사로잡혀 예언을 하고, 급기야 사울 자신까지도 하나님의 영 앞에 무력해집니다. \n\n벗은 몸으로 하루 밤낮을 누워 있는 사울의 모습은 하나님 앞에서 인간의 권력이 얼마나 무력한지를 보여주는 동시에, 하나님께서 당신의 택하신 자를 보호하시는 방법이 얼마나 주권적인지를 드러냅니다. 하나님께서는 요나단의 우정, 미갈의 기지, 그리고 성령의 직접적인 개입을 통해 다윗을 지키셨습니다.', E'오늘의 핵심\n하나님께서는 사울의 집요한 추격 속에서도 여러 사람과 초자연적인 방법을 통해 다윗을 보호하시며, 당신의 계획은 인간의 악의로도 막을 수 없음을 보여주십니다.\n\n묵상 질문\n1. 위기의 순간에 하나님께서 예상치 못한 사람이나 방법으로 나를 도우신 경험이 있나요?\n2. 요나단처럼 옳은 일을 위해 권위에 맞서야 할 때, 나는 어떤 선택을 하고 있나요?\n3. 하나님의 영 앞에서 무력해진 사울을 보며, 내가 놓아야 할 집착은 무엇인지 생각해봅시다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-14', E'시편 59편 사울에게 쫓기는 다윗', E'사무엘상 19장', E'사울의 질투가 살의로 변하면서 다윗의 생명이 위태로워집니다. 사울은 아들 요나단과 모든 신하들에게 다윗을 죽이라 명령하지만, 요나단의 사랑과 지혜로운 간청이 다윗을 보호합니다. 요나단은 아버지에게 다윗이 왕에게 득죄한 일이 없으며, 오히려 블레셋 사람을 물리쳐 이스라엘에 큰 구원을 가져왔음을 상기시킵니다. 이에 사울은 잠시 마음을 돌이켜 다윗을 죽이지 않겠다고 맹세합니다.\n\n그러나 사울의 변심은 오래가지 못합니다. 다윗이 또다시 블레셋과의 전쟁에서 큰 승리를 거두자, 악령에 사로잡힌 사울은 단창으로 다윗을 벽에 박으려 합니다. 간신히 목숨을 건진 다윗은 아내 미갈의 도움으로 창문을 통해 탈출하고, 미갈은 우상과 염소 털로 다윗이 병들어 누워있는 것처럼 위장합니다. 이 일로 사울의 딸까지도 다윗의 편에 서게 된 것을 본문은 보여줍니다.\n\n도망친 다윗은 라마에 있는 사무엘을 찾아갑니다. 어린 시절 자신에게 기름을 부었던 선지자에게로 돌아간 것입니다. 사울이 다윗을 잡으려 여러 차례 전령들을 보내지만, 놀랍게도 그들이 나욧에 이르자 하나님의 영이 임하여 모두 예언을 합니다. 급기야 사울 자신도 라마로 가지만, 그 역시 하나님의 영에 사로잡혀 옷을 벗고 하루 밤낮을 예언하며 누워있게 됩니다. "사울도 선지자 중에 있느냐"라는 속담이 생긴 배경입니다.\n\n이 장면은 하나님께서 당신의 기름 부은 자를 보호하시는 주권적인 역사를 보여줍니다. 인간의 살의와 권력도 하나님의 뜻을 거스를 수 없으며, 오히려 하나님께서는 다윗을 해하려던 자들조차 예언하게 하심으로써 당신의 능력을 나타내십니다. 사울은 왕이었지만 하나님의 영 앞에서는 무력한 존재일 뿐이었습니다.', E'오늘의 핵심\n하나님께서는 요나단과 미갈의 사랑, 그리고 성령의 초자연적인 역사를 통해 다윗을 사울의 살의로부터 보호하십니다. 인간의 악한 계획도 하나님의 주권적인 섭리를 막을 수 없습니다.\n\n묵상 질문\n1. 나를 위해 생명의 위험을 무릅쓰고 도와준 요나단과 미갈 같은 사람이 있나요?\n2. 하나님의 영이 원수까지도 예언하게 하신 것처럼, 나의 대적자를 위해서도 기도할 수 있을까요?\n3. 위기의 순간에 사무엘을 찾아간 다윗처럼, 나는 누구에게 영적인 도움을 구하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-16', E'예루살렘의 함락 (에스겔 33장)', E'에스겔 33장', E'포로로 끌려온 지 12년째, 예루살렘이 함락되었다는 소식이 에스겔에게 전해집니다. 도망친 자가 전한 이 비보는 포로민들에게 마지막 희망마저 무너뜨리는 절망의 선고였습니다. 하나님께서는 이러한 상황에서 에스겔을 다시 한번 이스라엘의 파수꾼으로 세우시며, 새로운 사명을 부여하십니다.\n\n파수꾼의 비유를 통해 하나님께서는 영적 지도자의 막중한 책임을 보여주십니다. 파수꾼이 위험을 보고도 나팔을 불지 않으면 백성의 피를 그의 손에서 찾겠다는 엄중한 경고는, 하나님의 말씀을 전하는 자의 사명이 얼마나 절박한지를 일깨워줍니다. 에스겔은 악인에게 경고하여 돌이키게 하는 것이 자신의 생명을 보전하는 길임을 깨닫게 됩니다.\n\n그러나 하나님의 마음은 심판 자체에 있지 않습니다. "나는 악인이 죽는 것을 기뻐하지 아니하고 악인이 그의 길에서 돌이켜 떠나 사는 것을 기뻐하노라"(겔 33:11)는 말씀은 하나님의 본심을 드러냅니다. 죄악으로 인해 쇠퇴하는 백성들의 절망적인 탄식에도 불구하고, 하나님께서는 여전히 돌이킬 기회를 주시며 생명의 길로 초청하고 계신 것입니다.\n\n예루살렘에 남아있던 자들은 오히려 교만하게도 아브라함의 예를 들며 땅의 소유권을 주장합니다. 그들은 우상숭배와 살인, 간음 등 온갖 죄악을 행하면서도 하나님의 약속을 자신들의 것으로 여겼습니다. 이에 하나님께서는 그들의 교만을 꺾으시고 땅을 황무지로 만들 것을 선언하십니다.\n\n한편 포로민들은 에스겔의 설교를 듣기 위해 모여들지만, 마치 음악을 감상하듯 귀로만 듣고 마음으로는 받아들이지 않습니다. 그들은 입으로는 사랑을 나타내지만 마음으로는 여전히 이익을 따르고 있었습니다. 그러나 하나님께서는 말씀이 반드시 이루어질 때 그들이 참 선지자가 자기들 가운데 있었음을 알게 될 것이라고 말씀하십니다.', E'오늘의 핵심\n예루살렘이 함락된 절망적 상황에서도 하나님께서는 여전히 회개와 생명의 길을 제시하시며, 파수꾼된 자들에게 그 메시지를 전할 책임을 부여하십니다.\n\n묵상 질문\n1. 나는 주변 사람들에게 하나님의 경고와 사랑을 전하는 영적 파수꾼의 역할을 감당하고 있나요?\n2. 하나님의 말씀을 단순히 듣기 좋은 소리로만 여기고 실천하지 않는 모습은 없나요?\n3. 절망적인 상황에서도 악인의 회개를 기뻐하시는 하나님의 마음을 어떻게 나눌 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-08-17', E'예루살렘의 함락 (에스겔 34장)', E'에스겔 34장', E'이스라엘의 목자들을 향한 하나님의 준엄한 심판이 선포됩니다. 에스겔을 통해 전해지는 메시지는 양 떼를 돌보아야 할 목자들이 오히려 양들을 착취하고 자기 배만 불리는 타락한 현실을 고발합니다. 목자들은 살진 양을 잡아먹고 그 털로 옷을 해 입으면서도 정작 양 떼는 돌보지 않았습니다. 연약한 자를 강하게 하지 않고, 병든 자를 고치지 않으며, 상한 자를 싸매주지 않았습니다. 흩어진 자를 찾지도 않고 오직 포악으로 다스렸던 것입니다.\n\n목자를 잃은 양들은 산과 들에 흩어져 들짐승의 밥이 되었습니다. 이러한 비극적 상황에 하나님께서 직접 개입하십니다. "내가 친히 내 양의 목자가 되어"(겔 34:15)라는 선언은 실패한 인간 지도자들을 대신하여 하나님께서 직접 목자가 되시겠다는 약속입니다. 하나님은 흩어진 양을 찾아 모으시고, 좋은 꼴을 먹이시며, 상한 자를 싸매주고 병든 자를 강하게 하실 것입니다.\n\n더 나아가 하나님은 "내 종 다윗"을 세워 참된 목자가 되게 하시겠다고 약속하십니다. 이는 단순히 과거 다윗 왕조의 회복이 아니라, 다윗의 후손으로 오실 메시아를 가리키는 예언입니다. 그 목자 아래에서 이스라엘은 화평의 언약을 누리며, 악한 짐승의 위협 없이 평안히 거하게 될 것입니다. 때를 따라 내리는 복된 소낙비와 풍성한 열매, 그리고 "나는 너희 하나님이라"는 언약의 회복이 약속됩니다.\n\n이스라엘의 실패한 지도자들에 대한 심판 선언은 동시에 하나님의 신실한 돌보심에 대한 약속이기도 합니다. 인간 지도자의 실패가 하나님의 계획을 좌절시킬 수 없으며, 오히려 하나님께서 친히 목자가 되어 주심으로써 더 완전한 구원이 이루어질 것을 보여줍니다.', E'오늘의 핵심\n실패한 목자들을 심판하시는 하나님은 친히 참 목자가 되어 흩어진 양 떼를 모으시고, 메시아를 통한 완전한 회복을 약속하십니다.\n\n묵상 질문\n1. 내게 맡겨진 영혼들을 섬기는 일에 있어서 자기 유익을 먼저 구하지는 않았나요?\n2. 하나님께서 친히 목자가 되신다는 약속이 오늘 나에게 주는 위로는 무엇인가요?\n3. 연약한 자를 돌보고 흩어진 자를 찾는 일에 나는 어떻게 동참할 수 있을까요?');
